INSERT INTO `mdt_charges` (`id`, `title`, `description`, `classType`, `colour`, `months`, `fine`, `chargeType`) VALUES
	(1, 'Simple Assault', 'Refers to an attempt or threat to inflict physical harm on someone without the use of a weapon and without causing serious injury such as hitting, slapping, shoving or even verbal threats that create a reasonable fear of imminent harm.', 'Misdemeanor', 'green', 5, 2000, 'offenses against persons'),
	(2, 'Assault', 'Intentional act that creates a reasonable fear or apprehension of imminent harmful or offensive contact in another person, it does not necessarily require physical content, the mere threat of harm can qualify as assault if the victim believes the threat is real and immediate.', 'Misdemeanor', 'yellow', 10, 1500, 'offenses against persons'),
	(3, 'Aggravated Assault', 'Serious form of assault that typically involves actions intending to cause significant bodily harm or the use of a deadly weapon. It goes beyond simple assault because of the severity of the intent, the injury caused, or the method used to commit the assault.', 'Felony', 'yellow', 30, 17500, 'offenses against persons'),
	(4, 'Assault with a Deadly Weapon', '(ADW) Refers to the act of assaulting someone using a weapon or object that is capable of causing serious bodily injury, involvement of a deadly weapon such as gun, knife, bat, or any other item that could potentially inflict significant harm.', 'Felony', 'red', 30, 5000, 'offenses against persons'),
	(5, 'Involuntary Manslaughter', 'Involves the unintentional killing of another person without malice and lacks the element of premeditation or intentional. Occurs as a result of reckless or negligent actions that lead to someoneÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s death but without the intent to kill (Character has officially died)', 'Felony', 'red', 60, 8500, 'offenses against persons'),
	(6, 'Vehicular Manslaughter', 'The unlawful killing of a person through the negligent or reckless operation of a vehicle, unlike murder, this does not require the intent to kill, but it involves a death caused by actions that show a disregard for the safety of others, or criminal negligence while driving.', 'Felony', 'red', 90, 20000, 'offenses against persons'),
	(7, 'Attempted Murder of a Civilian', 'Refers to an intentional and deliberate act by a person to kill another individual (a civilian in this case), where the victim does not die due to the defendants actions, while the person may not have succeeded in causing the death, they took substantial steps to carry out the murder.', 'Felony', 'red', 60, 15000, 'offenses against persons'),
	(8, 'Second Degree Murder', 'That involves the intentional killing of another person but without the premeditation or the specific intent required for first-degree murder, typically occurs in a fit of passion or due to recklessness rather than being planned in advance (Character has officially died).', 'Felony', 'red', 100, 15000, 'offenses against persons'),
	(9, 'Accessory to Second Degree Murder', 'Refers to someone who aids, abets, or assists another person in the commission of second-degree murder, without directly committing the act of murder themselves. An accessory typically helps the primary person either before or after the crime takes place but does not actually participate in the killing itself. (Character has officially died)', 'Felony', 'red', 60, 15000, 'offenses against persons'),
	(10, 'First Degree Murder', 'Any intentional or premeditated killing of another person, it is characterized by planning, deliberation and malice. This means the killer specially intended to cause the death of the victim and took steps to carry out the murder in advance.', 'Felony', 'red', 0, 0, 'offenses against persons'),
	(11, 'Accessory to First Degree Murder', 'Refers to a person who assists, aids, or facilitates the commission of first-degree murder, but does not directly carry out the act of murder themselves, the accessory helps the primary person either before or after the crime occurs, knowing that the murder is being planned or has been committed.', 'Felony', 'red', 0, 0, 'offenses against persons'),
	(12, 'Murder of a Public Servant or Peace Officer', 'Refers to the intentional killing of a peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service, while they are performing their official duties.', 'Felony', 'red', 0, 0, 'offenses against persons'),
	(13, 'Attempted Murder of a Public Servant or Peace Officer', 'Refers to the intentional act of trying to kill a peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service.', 'Felony', 'red', 65, 10000, 'offenses against persons'),
	(14, 'Accessory to the Murder of a Public Servant or Peace Officer', 'Refers to someone who assists, aids, abets, or assists in the commission of the murder of a pa peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service, without directly participating in the act of killing. The accessory helps the principal (the actual murderer) before or after the crime, knowing that the murder is being planned or has already occurred..', 'Felony', 'red', 0, 0, 'offenses against persons'),
	(15, 'Unlawful Imprisonment', 'The act of taking another against their will and holding them for an extended period of time', 'Misdemeanor', 'green', 10, 600, 'offenses against persons'),
	(16, 'Kidnapping', 'The Unlawful taking, carrying away, or detaining a person by force, threat, or deception, with the intent to hold them against their will. The Key element of kidnapping is that the victim is moved in some way without their consent and typically involves some level of threat and or force.', 'Felony', 'yellow', 15, 900, 'offenses against persons'),
	(17, 'Accessory to Kidnapping', 'BeinRefers to a person who assists, aids, or facilitates another individual in committing the crime of kidnapping, without directly participating in the act of taking or confining the victim. The accessory helps the primary person before or after the kidnapping occurs, knowing that the crime is being planned or has been carried out.', 'Felony', 'yellow', 15, 1000, 'offenses against persons'),
	(18, 'Attempted Kidnapping', 'Refers to the act of trying to unlawfully take or restrain another person with the intent to kidnap, but failing to complete the crime. The key element is that the defendant took substantial steps towards kidnapping such as attempting to physically restrain or move the victim but did not succeed in actually taking or confining the victim.', 'Felony', 'yellow', 10, 10000, 'offenses against persons'),
	(19, 'Hostage Taking', 'Refers to the act of seizing and holding another person against their will, typically to use them as leverage in order to achieve a specific goal or demand.', 'Felony', 'yellow', 45, 2500, 'offenses against persons'),
	(20, 'Accessory to Hostage Taking', 'Refers to a person who assists, aids, or facilitates another individual in the commission of hostage taking, without directly participating in the act of seizing or holding the hostage, The Accessory helps the principal (the actual perpetrator) either before or after the crime occurs, knowing that a hostage is being taken or has been taken.', 'Felony', 'yellow', 20, 1200, 'offenses against persons'),
	(21, 'Kidnapping of a Public Servant or Peace Officer', 'Refers to the act of unlawful taking or detaining of a peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service against their will, with the intent to hold them for ransom, for some criminal purpose, or to prevent them for carrying their duties.', 'Felony', 'yellow', 50, 8000, 'offenses against persons'),
	(22, 'Criminal Threats', 'Refers to the act of intentionally threatening to cause harm or death to another person, with the specific intent to place that person in fear for their safety or the safety of their loved ones. The threat must be communicated in such a way that the victim perceives it as a genuine, immediate threat.', 'Misdemeanor', 'yellow', 5, 500, 'offenses against persons'),
	(23, 'Reckless Endangerment', 'Refers to the act of creating a substantial risk of harm or injury to another person through reckless behaviour without regard for the potential consequences. The key element is that the individual act', 'Misdemeanor', 'yellow', 10, 1000, 'offenses against persons'),
	(24, 'Gang Related Shooting', 'Any individual who, with one or more members of their ÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬Ãâ¦Ã¢â¬ÅgangÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃâÃÂ engages in a shooting/shootout with two or more members of other gangs', 'Felony', 'red', 20, 5000, 'offenses against persons'),
	(25, 'DELETE', 'The act in which a persons consumes the flesh of another willingly', 'Felony', 'red', 0, 0, 'offenses against persons'),
	(26, 'Torture', 'The act of causing harm to another to extract informaion and or for self enjoyment', 'Felony', 'red', 40, 4500, 'offenses against persons'),
	(27, 'Attempted Aggravated Assault', 'Refers to an act where someone takes significant steps towards committing aggravated assault but does not successfully complete the crime, it still involves intent and action that could result in serious harm or involve a deadly weapon, but no serious injury or harm actually occurs.', 'Misdemeanor', 'red', 22, 10000, 'offenses against persons'),
	(28, 'Assault of a Public Servant or Peace Officer', 'Refers to an intentional attack or threat of violence directed at a law enforcement office or other public officials while they are performing their official duties, this includes Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service', 'Felony', 'red', 48, 10000, 'offenses against persons'),
	(29, 'Attempt Assault of a Public Servant or Peace Officer', 'Refers to an intentional act where someone takes substantial steps towards assaulting a peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service, while they are performing their official duties but the assault is not successfully completed.', 'Misdemeanour', 'yellow', 15, 1500, 'offenses against persons'),
	(30, 'Accessory to the Attempted Murder of a Public Servant or Peace Officer', 'Refers to someone who assists, aids, or facilitates another person in the act of attempting to kill a peace officer or public servant such as Police Officers, Sheriffs Deputies, Paramedics, or other individuals working in roles related to public safety or government service. The Accessory helps the primary offender either before or after the crime occurs knowing that the crime is being planned or has been committed.', 'Felony', 'red', 30, 6000, 'offenses against persons'),
	(31, 'Accessory to Aggravated Assault', 'Refers to someone who assists, aids, or facilitates another person in the act of a serious form of assault that typically involves actions intending to cause significant bodily harm or the use of a deadly weapon. It goes beyond simple assault because of the severity of the intent, the injury caused, or the method used to commit the assault. This charge is appropriate for individuals who are involved in a mass shooting, where individual assaults cannot be identified.', 'Felony', 'red', 20, 6000, 'offenses against persons'),
	(32, 'Theft', 'The Act of taking someone elseÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s property without their permission with the intent to permanently deprive them of it with the value up to $1,000', 'Infraction', 'green', 0, 800, 'offenses involving theft'),
	(33, 'Grand Theft', 'Unlawfully taking property of significant value ($1,000 for more) with the intent to permanently deprive the owner of it.', 'Misdemeanor', 'green', 10, 1000, 'offenses involving theft'),
	(34, 'Joyriding', 'The Act of taking and driving someone elseÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s vehicle without their permission. Typically for temporary use and without the intent to permanently deprive the owner of it.', 'Misdemeanour', 'green', 12, 900, 'offenses involving theft'),
	(35, 'Grand Theft Auto', 'The act of unlawfully taking possession of a motor vehicle with the intent to permanently deprive the rightful owner of their property. This includes actions taken to obscure the vehicles identity or ownership, such as: Destroying the vehicle. Removing or tampering with license plates, Vehicle Identification Numbers (VINs), or tracking devices. Altering or disguising the vehicle for resale or personal use (e.g., VIN scratches, chopping vehicles, or disabling trackers).', 'Felony', 'green', 25, 5000, 'offenses involving theft'),
	(36, 'Carjacking', 'The Act of forcibly taking a vehicle directly from its driver or occupants through the use of violence, intimidation, or threats. Carjacking combines elements of theft and assault.', 'Felony', 'yellow', 25, 3500, 'offenses involving theft'),
	(37, 'Burglary', 'The Unlawful entry into a building, structure, or dwelling with the intent to commit a crime, especially theft. The entry does not necessarily involve breaking in or force; simply gaining unauthorized access can constitute burglary if criminal intent is present..', 'Misdemeanor', 'green', 15, 1000, 'offenses involving theft'),
	(38, 'Robbery', 'The Act of taking property directly from another person through the use of force, intimidation, or threats, unlike theft, robbery involves personal confrontation and often includes violence or the threat of harm. Unlike Burglary which involves unlawful entry and theft, which may not involve direct interaction with the victim.', 'Felony', 'green', 20, 2000, 'offenses involving theft'),
	(39, 'Accessory to Robbery', 'Refers to a person who aids, assists, or encourages the commission of a robbery but does not directly participate in the act itself. This can occur before or after the robbery. Key Elements Before the robbery: Providing help, such as planning, supplying tools, or acting as a lookout After the robbery: Assisting the offender, such as hiding stolen property or helping them evade law enforcement.', 'Felony', 'green', 12, 1000, 'offenses involving theft'),
	(40, 'Attempted Robbery', 'The Act of trying to commit a robbery but failing to complete it, involves taking significant steps towards robbing someone, such as using threats or force to take property but not successfully obtaining the property.', 'Felony', 'green', 20, 1000, 'offenses involving theft'),
	(41, 'Armed Robbery', 'The Action in which the offender uses or threatens to use a weapon to intimidate or coerce the victim while stealing property, the weapon can include firearms, knives, baseball bats, or any object that is capable of causing harm.', 'Felony', 'yellow', 20, 3000, 'offenses involving theft'),
	(42, 'Accessory to Armed Robbery', 'Person(s) who assist or facilitate the commission of an armed robbery but are not the one directly committing the crime. This can include providing support, such as planning the robbery, supplying weapons or vehicles, or helping perpetrators evade law enforcement. Accessory can occur before, during or after the crime.', 'Felony', 'yellow', 15, 1500, 'offenses involving theft'),
	(43, 'Attempted Armed Robbery', 'When an individual(s) takes steps towards committing a robbery while armed with a weapon but does not complete the act. This involves the intent to steal and the use of threat of force, along with the possession of firearms, knives, baseball bats, or any object that is a dangerous weapon. Even if the robbery is not successfully carried.', 'Felony', 'yellow', 18, 1500, 'offenses involving theft'),
	(44, 'Grand Larceny', 'The Unlawful taking of someone elses property with the intent to permanently deprive the owner of it, where the value of the stolen property exceeds the amount of Grand Theft.', 'Felony', 'yellow', 35, 7500, 'offenses involving theft'),
	(45, 'Leaving Without Paying', 'The Act of leaving business, such as a restaurant, store, or service provider, without paying for the goods or services received. Can also be known as Dine and Dash in the context of restaurants.', 'Infraction', 'green', 0, 1000, 'offenses involving theft'),
	(46, 'Possession of Nonlegal Currency', 'Refers to having currency that is not recognized as legal tender by a government or authority. This could include counterfeit money.', 'Misdemeanor', 'green', 15, 1500, 'offenses involving theft'),
	(47, 'Possession of Items Used in the Commission of a Crime', 'Being in Possession of objects or tools that are commonly associated with illegal activities. These items could include weapons, drugs, burglary tools, or other materials that are used to commit a crime.', 'Misdemeanor', 'green', 10, 500, 'offenses involving theft'),
	(48, 'Sale of Items Used in the Commission of a Crime', 'The Act of selling items that are intended or commonly used to commit illegal activities. This can include selling weapons, drugs, stolen property, or tools used for committing crime like burglary for fraud.', 'Felony', 'yellow', 15, 1000, 'offenses involving theft'),
	(49, 'Theft of an Aircraft', 'The act of stealing an aircraft', 'Felony', 'green', 20, 1000, 'offenses involving theft'),
	(50, 'Robbery of a Government Employee', 'The Act of using force, threats, or intimidation to steal property or money from a government employee(s), this includes but not limited to LEO, EMS & DOJ The Crime involves not only theft but also the use of violence or the threat of violence.', 'Felony', 'red', 75, 7500, 'offenses involving theft'),
	(51, 'Prostitution', 'The act of soliciting money in exchange for intimate acts', 'Felony', 'yellow', 35, 3500, 'offenses involving theft'),
	(52, 'Accessory to the Robbery of a Government Employee', 'Refers to a person(s) who assists or aids someone in committing the robbery of a government employee, either before or after the crime occurs. An Accessory may not directly participate in the robbery but can be solved by providing support, such as helping plan the crime, supply tools/weapons or helping the perpetrator escape afterward.', 'Felony', 'yellow', 50, 5000, 'offenses involving theft'),
	(53, 'Robbery of a Local Financial Institution (Fleeca or Paleto Bank)', 'The unlawful entry or attempted entry into a small-scale financial institution, such as Fleeca Bank, with the intent to commit theft, armed robbery, or extortion.', 'Felony', 'red', 50, 15000, 'offenses involving theft'),
	(54, 'Robbery of a Local Financial Institution (Pacific Standard Bank)', 'The unlawful entry or attempted entry into a high-security, large-scale financial institution, such as Pacific Standard Bank, with the intent to commit theft, armed robbery, or extortion.', 'Felony', 'red', 70, 30000, 'offenses involving theft'),
	(55, 'Impersonating', 'The Act of pretending to be another person, entity, or official in order to deceive, mislead, or gain advantage. It could be done verbally, in writing, or through actions.', 'Misdemeanor', 'green', 15, 1250, 'offenses involving fraud'),
	(56, 'Impersonating a Peace Officer or Public Servant', 'The illegal act of pretending to be a law enforcement officer, government official, or other public servant with the intent to deceive, intimidate, or gain unlawful advantage.', 'Felony', 'green', 25, 2750, 'offenses involving fraud'),
	(57, 'Impersonating a Judge', 'The illegal act of falsely presenting oneself as a judge with the intent to deceive, manipulate, or gain an unlawful advantage.', 'Felony', 'red', 0, 0, 'offenses involving fraud'),
	(58, 'Possession of Stolen Identification', 'The illegal act of knowingly possessing or using someone elses identification or personal information that was obtained by theft, fraud, or other unlawful means.', 'Misdemeanor', 'green', 10, 750, 'offenses involving fraud'),
	(59, 'Possession of Stolen Government Identification', 'The illegal act of possessing or using government-issued identification that has been obtained through theft or fraud.', 'Misdemeanor', 'green', 20, 2000, 'offenses involving fraud'),
	(60, 'Extortion', 'The act of obtaining money, goods, services, or other benefits from someone through the use of threats, force, intimidation, or coercion. The threat can harm the victim physically, damage their property, expose personal information.', 'Felony', 'yellow', 20, 900, 'offenses involving fraud'),
	(61, 'Fraud', 'The intentional deception or misrepresentation of facts for personal gain or to cause harm to another person. It involves using dishonest means to manipulate others into giving up money, property, or other value assets. Key elements described in online penal code.', 'Misdemeanor', 'green', 10, 450, 'offenses involving fraud'),
	(62, 'Forgery', 'The Act of falsely making, altering, or initialing a document, signature, or other items with the intent to deceive or defraud. See online penal code for key elements.', 'Misdemeanor', 'green', 15, 750, 'offenses involving fraud'),
	(63, 'Money Laundering', 'The process of concealing the origins of illegally obtained money, typically by means of transfers or transactions that make the money appear legitimate. See key elements online.', 'Felony', 'red', 0, 0, 'offenses involving fraud'),
	(64, 'Trespassing', 'The Act of entering someone elses property or land without permission. It typically involves unlawfully crossing boundaries , whether physical (like fences) or implied (like signs or private property markings) Trespassing can also refer to staying on a property after being asked to leave or using the property in ways not authorized by the owner.', 'Misdemeanor', 'green', 10, 800, 'offenses involving damage to property'),
	(65, 'Felony Trespassing', 'For a person to have repeatedly entered the bounds of a location of which they are knowingly not legally allowed', 'Felony', 'green', 15, 1500, 'offenses involving damage to property'),
	(66, 'Arson', 'The Act of intentionally setting fire to property, land, or structures without legal permission, often causing damage or destruction.', 'Felony', 'yellow', 15, 1500, 'offenses involving damage to property'),
	(67, 'Vandalism', 'The Act of damaging, defacing, or destroying someone elses property without their permission. It can include acts such as graffiti, breaking windows, damaging vehicles, or tampering with public or private property.', 'Infraction', 'green', 0, 1000, 'offenses involving damage to property'),
	(68, 'Vandalism of Government Property', 'The Act of damaging, defacing, or destroying property owned by a government entity, such as buildings, monuments, vehicles.', 'Felony', 'green', 20, 1500, 'offenses involving damage to property'),
	(69, 'Littering', 'The act of improperly disposing of waste or trash in an area where it does not belong, such as streets, parks, other public or private areas, instead of using designated trash or recycling bins.', 'Infraction', 'green', 0, 200, 'offenses involving damage to property'),
	(70, 'Bribery of a Government Official', 'The Act of offering, giving, receiving, or soliciting something of value (such as money, gifts, or favors) to influence the actions, decisions, or duties of government official in an unlawful or unethical manner.', 'Felony', 'green', 20, 3500, 'offenses against public administration'),
	(71, 'Anti-Mask Law', 'Wearing a mask, face coverings, or disguises in public spaces to conceal their identity.', 'Infraction', 'green', 0, 750, 'offenses against public administration'),
	(72, 'Possession of Contraband in a Government Facility', 'The Act of having prohibited items, such as weapons, drugs, or unathorized devices within a facility owned or operated by the government, such as Courthouses, Prisons, or military bases.', 'Felony', 'green', 25, 1000, 'offenses against public administration'),
	(73, 'Criminal Possession of Stolen Property', 'The Act of knowingly having in your possession items that have been stolen, with the intent to benefit from them or prevent their rightful owner from reclaiming them.', 'Misdemeanor', 'green', 10, 500, 'offenses against public administration'),
	(74, 'Escaping', 'The Act of a person who is being held in custody, such as police, prison authorities, or other law enforcement, breaking free and fleeing from the detention without permission.', 'Felony', 'green', 10, 1000, 'offenses against public administration'),
	(75, 'Jailbreak', 'The Act of breaking out of prison or jail, typically involves escaping from a secure facility where the individual is being held in custody. Jailbreaks can be planned or spontaneous and may involve physical force, deception, or assistance from outside sources.', 'Felony', 'yellow', 30, 2500, 'offenses against public administration'),
	(76, 'Accessory to Jailbreak', 'Refers to a person who helps, aids, or assists someone in escaping from prison or jail without directly participating in the escape itself. This can include providing tools, planning escape, or offering any form of support, such as acting as a lookout or helping the escapee evade capture.', 'Felony', 'yellow', 25, 2000, 'offenses against public administration'),
	(77, 'Attempted Jailbreak', 'The Act of attempting to escape from prison or jail, but not succeeding in the escape, it involves planning, preparing, or trying to break out of custody.', 'Felony', 'yellow', 25, 1500, 'offenses against public administration'),
	(78, 'Perjury', 'The Act of knowingly lying or providing false information while under oath, typically during legal proceedings such as court testimony or sworn affidavits. ONLINE FOR GUILTY', 'Felony', 'green', 0, 0, 'offenses against public administration'),
	(79, 'Violation of a Restraining Order', 'When an individual knowingly disobeys the terms set in a legal order that prohibits them from contacting or coming near another person.', 'Felony', 'green', 20, 2250, 'offenses against public administration'),
	(80, 'Embezzlement', 'The Act of unlawfully taking or misappropriating funds or property that has been entrusted to someoneÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s care.', 'Felony', 'green', 45, 10000, 'offenses against public administration'),
	(81, 'Unlawful Practice', 'Refers to engaging in an activity or profession without the proper legal authorization, certification, or license, or in a violation of specific laws or regulations. ONLINE FOR MORE', 'Felony', 'yellow', 15, 1500, 'offenses against public administration'),
	(82, 'Misuse of Emergency Systems', 'The Act of intentionally or recklessly using emergency services, such as 911/311 or other emergency response systems, for non-emergency purposes. ', 'Infraction', 'yellow', 0, 1000, 'offenses against public administration'),
	(83, 'Conspiracy', 'The Act of two or more individuals planning or agreeing to commit a criminal act or series of criminal acts. The key element of conspiracy is the intention to commit the crime and the collaboration to carry out illegal activity, even if the crime is not actually carried out.', 'Misdemeanor', 'green', 10, 800, 'offenses against public administration'),
	(84, 'Violating a Court Order', 'When an individual fails to comply with a directive or ruling issued by a court. GUILTY 24mo 20K', 'Misdemeanor', 'yellow', 0, 0, 'offenses against public administration'),
	(85, 'Failure to Appear', 'Refers to the crime of not showing up for a scheduled court hearing or legal proceeding after being required to do so. GUILTY 15mo 20K', 'Misdemeanor', 'yellow', 0, 0, 'offenses against public administration'),
	(86, 'Contempt of Court', 'Refers to behavior that disrupts or disobeys the authority, rules, orders of a court. It can involve actions that disrupt courting proceedings, such as refusing to follow a court order, showing disrespect toward legal authorities, or behaving inappropriately during a trial.  (judicial decision)', 'Felony', 'yellow', 0, 0, 'offenses against public administration'),
	(87, 'Resisting Arrest', 'The Act of actively opposing or interfering with a law enforcement officer who is attempting to make an arrest. This can include physical actions such as fighting, fleeing, or using force to prevent the officer from detaining or arresting the individual.', 'Misdemeanor', 'yellow', 15, 500, 'offenses against public administration'),
	(88, 'Disobeying a Peace Officer', 'The willful disregard of a lawful order', 'infraction', 'green', 0, 750, 'offenses against public order'),
	(89, 'Disorderly Conduct', 'Acting in a manner that creates a hazardous or physically offensive condition by any act which serves no legitimate purpose of the actor. ', 'Infraction', 'green', 0, 250, 'offenses against public order'),
	(90, 'Disturbing the Peace', 'Action in a manner that causes unrest and disrupts public order', 'infraction', 'green', 0, 350, 'offenses against public order'),
	(91, 'False Reporting', 'The act of reporting a crime that did not happen', 'Misdemeanor', 'green', 10, 750, 'offenses against public order'),
	(92, 'Harassment', 'The repeated disruption or verbal attacks of another person', 'Misdemeanor', 'yellow', 10, 500, 'offenses against public order'),
	(93, 'Misdemeanor Obstruction of Justice', 'The Act of intentionally interfering with the legal process or law enforcement. This can involve obstructing an investigation, hindering a police officer, or disrupting a court proceeding. SEE ONLINE FOR EXAMPLES', 'Misdemeanor', 'green', 10, 500, 'offenses against public order'),
	(94, 'Felony Obstruction of Justice', 'When a person intentionally interferes with law enforcement or the legal process in a way that significantly disrupts justice. This can include actions that impede investigations, legal proceedings, or the administration of justice in a substantial manner. SEE ONLINE FOR EXAMPLES', 'Felony', 'yellow', 45, 10000, 'offenses against public order'),
	(95, 'Inciting a Riot', 'Causing civil unrest in a manner to incite a group to cause harm to people or property', 'Felony', 'yellow', 25, 1000, 'offenses against public order'),
	(96, 'Loitering on Government Properties', 'When someone is present in a government proper for an extended period of time', 'Infraction', 'green', 0, 500, 'offenses against public order'),
	(97, 'Tampering', 'When someone willfully, knowingly and indirectly interfering with key points of a lawful investigation', 'Misdemeanor', 'green', 10, 500, 'offenses against public order'),
	(98, 'Vehicle Tampering', 'The willful and knowing interference the normal function of a vehicle', 'Misdemeanor', 'green', 15, 750, 'offenses against public order'),
	(99, 'Evidence Tampering', 'The willful and knowing interference with evidence from a lawful investigation', 'Felony', 'green', 20, 1000, 'offenses against public order'),
	(100, 'Witness Tampering', 'The willful and knowing coaching or coercing of a witness in a lawful investigation', 'Felony', 'green', 0, 0, 'offenses against public order'),
	(101, 'Failure to Provide Identification', 'The act of not presenting identification when lawfully required to do so', 'Misdemeanor', 'green', 15, 1500, 'offenses against public order'),
	(102, 'Vigilantism', 'The act of engaging in enforcing the law with legal authority to do so', 'Felony', 'yellow', 30, 1500, 'offenses against public order'),
	(103, 'Unlawful Assembly', 'when a large group gathers in a location that requires prior approval to do so', 'Misdemeanor', 'yellow', 10, 750, 'offenses against public order'),
	(104, 'Official Misconduct', 'Willfully violating the law or department policy while performing sworn duties', 'Felony', 'red', 100, 50000, 'offenses against public order'),
	(105, 'Stalking', 'When one person monitors another without their consent', 'Felony', 'yellow', 40, 1500, 'offenses against public order'),
	(106, 'Aiding and Abetting', 'To assist someone in committing or to encourage someone to commit a crime', 'Misdemeanor', 'yellow', 15, 450, 'offenses against public order'),
	(107, 'Harboring a Fugitive', 'When someone willingly hides another who is wanted by the authorities', 'Misdemeanor', 'green', 10, 1000, 'offenses against public order'),
	(108, 'Misdemeanor Possession of Marijuana', 'The Act of knowingly or intentionally possessing a small amount of Marijunan (Cannabis), either in a raw form, seeds or prepared for consumption (Less Than 10 but greater than 4)', 'Misdemeanor', 'green', 10, 500, 'offenses against health and morals'),
	(109, 'Felony Possession of Marijuana', 'The Act of knowingly or intentionally possessing a large quantity of marijuana (Cannabis) either in a raw form, seeds or prepared for consumption (More Than 10)', 'Felony', 'yellow', 15, 1000, 'offenses against health and morals'),
	(110, 'Misdemeanour Cultivation of Marijuana', 'The Act of knowingly or intentionally growing, planting, harvesting, or producing marijuana plants, typically without authorization under state or federal law. It encompasses all stages of the growth process, from planting seeds to harvesting the mature plant. (4 or more no greater than 10 Marijuana Plants)', 'Misdemeanor', 'green', 25, 2000, 'offenses against health and morals'),
	(111, 'Felony Cultivation of Marijuana', 'The Unauthorized growing, planting, or harvesting marijuana plants in amounts or circumstances that exceed legal limits (10 or more marijuana plants).', 'Felony', 'yellow', 60, 10000, 'offenses against health and morals'),
	(112, 'Possession of Marijuana with Intent to Distribute', 'The Unlawful possession of marijuana combined with evidence suggesting an intention to sell, distribute or transfer it to others.', 'Felony', 'yellow', 30, 3000, 'offenses against health and morals'),
	(113, 'Misdemeanor Possession of Cocaine', 'The possession of cocaine in a small quantity usually for personal use', 'Misdemeanor', 'yellow', 25, 2500, 'offenses against health and morals'),
	(114, 'Felony manufacturing Possession of Cocaine', 'The Unlawful production, processing, or possession of Cocaine, typically involving chemical synthesis or extraction, with the intent to distribute or sell.', 'Felony', 'red', 150, 150000, 'offenses against health and morals'),
	(115, 'Possession of Cocaine with Intent to Distribute', 'The Unlawful possession of cocaine combined with evidence suggesting an intention to sell, distribute or transfer it to others', 'Felony', 'yellow', 45, 30500, 'offenses against health and morals'),
	(116, 'Misdemeanor Possession of Methamphetamine', 'The illegal possession of a small amount of methamphetamine (Less than 5 small bags)', 'Misdemeanor', 'green', 35, 500, 'offenses against health and morals'),
	(117, 'Felony manufacturing Possession of Methamphetamine', 'The Unlawful production, processing, or possession of Methamphetamine, typically involving chemical synthesis or extraction, with the intent to distribute or sell.', 'Felony', 'red', 150, 150000, 'offenses against health and morals'),
	(118, 'Possession of Methamphetamine with Intent to Distribute', 'The illegal possession with the purpose of selling, delivering, or otherwise distributing it to others.', 'Felony', 'yellow', 35, 4500, 'offenses against health and morals'),
	(119, 'Misdemeanor Possession of Oxy / Vicodin', 'The illegal possession of Oxy/Vicodin without a valid prescription in small quantities usually for person use and without a label on the bottle. (less than 20).', 'Misdemeanor', 'green', 7, 500, 'offenses against health and morals'),
	(120, 'Felony Possession of Oxy / Vicodin', 'The illegal possession of oxy/vicodin (20 or more) bottles, without a valid prescription and or without a label on the bottle.', 'Felony', 'red', 15, 1500, 'offenses against health and morals'),
	(121, 'Felony Possession of Oxy / Vicodin with Intent to Distribute', 'The possession of a quantity of oxy / vicodin for distribution - Quantity of 20 (or more) bottles. Items as well as high-powered weapons, scales, baggies may inform this charge.', 'Felony', 'yellow', 35, 6500, 'offenses against health and morals'),
	(122, 'Sale of a controlled substance', 'The illegal act of selling or distributing drugs that are classified as controlled substances by law.', 'Misdemeanor', 'green', 10, 1000, 'offenses against health and morals'),
	(123, 'Drug Trafficking', 'The illegal act of transporting, distributing, or selling large quantities of controlled substances. It often involves the production, distribution, and sale of drugs such as Cannabis, Oxy, Cocaine, Meth or prescription medications without authorization. The large scale movement of illegal drugs. SEE ONLINE for up to date quantities.', 'Felony', 'red', 0, 0, 'offenses against health and morals'),
	(124, 'Desecration of a Human Corpse', 'The illegal and disrespectful act of mistreating, vandalizing, or damaging a dead body. This can include actions such as disinterring a body, mutilating it, or engaging in any form of disrespectful.', 'Felony', 'yellow', 20, 1500, 'offenses against health and morals'),
	(125, 'Public Intoxication', 'The offence of being visibly drunk or under the influence of drugs in a public place to the point where it endangers oneself or others, causing disturbance, or disrupts public peace.', 'Infraction', 'green', 0, 1000, 'offenses against health and morals'),
	(126, 'Public Indecency', 'Engaging in sexually explicit behavior or displaying inappropriate conduct in public places where others can see it. This can include actions like indecent exposure, lewd behavior, or engaging in sexual acts in view of the public.', 'Misdemeanor', 'green', 10, 750, 'offenses against health and morals'),
	(127, 'Possession of Drug Paraphernalia', 'The illegal possession of equipment or items designed or used for the purpose of manufacturing, using, or distributing illegal drugs. This can include items such as, scales, empty baggies, bongs.', 'Misdemeanor', 'green', 10, 750, 'offenses against health and morals'),
	(128, 'Grave-robbing', 'The illegal act of digging up and disturbing a grave, often with the intent to steal valuables or human remains. (YES THIS ALSO INCLUDES FAMILY MEMBERS).', 'Misdemeanour', 'green', 15, 1250, 'offenses against health and morals'),
	(129, 'Felony cultivation of a Marijuana Farm', 'Refers to the large-scale, illegal growing of marijuana plants, typically involving significant land use and infrastructure. (15 or more Marijuana plants or seeds in excess of 30 along with dried product greater than intent to distribute).', 'Misdemeanour', 'green', 120, 25000, 'offenses against health and morals'),
	(130, 'Felony Possession of Cocaine', 'The Illegal possession of a certain amount of Cocaine (more than 5 bags).', 'Misdemeanour', 'green', 35, 1000, 'offenses against health and morals'),
	(131, 'Criminal Possession of Weapon Class A', 'Possession of a bladed or blunt weapon in the commission of a violent crime.', 'Felony', 'green', 10, 500, 'offenses against public safety'),
	(132, 'Criminal Possession of Weapon Class B', 'Possession of a Class B firearm without licensing (Pistol)', 'Felony', 'yellow', 25, 10000, 'offenses against public safety'),
	(133, 'Criminal Possession of Weapon Class C', 'Possession of a Class C firearm without licensing (Shotgun/SMG)', 'Felony', 'red', 35, 12500, 'offenses against public safety'),
	(134, 'Criminal Possession of Weapon Class D', 'Possession of a Class D firearm without licensing (AR/Explosives)', 'Felony', 'red', 45, 15000, 'offenses against public safety'),
	(135, 'Criminal Sale of Weapon Class A', 'The act of selling a Class A weapon without license', 'Felony', 'yellow', 15, 1000, 'offenses against public safety'),
	(136, 'Criminal Sale of Weapon Class B', 'The act of selling a Class B firearm without licensing', 'Felony', 'yellow', 40, 25000, 'offenses against public safety'),
	(137, 'Criminal Sale of Weapon Class C', 'The act of selling a Class C firearm without licensing', 'Felony', 'yellow', 55, 25000, 'offenses against public safety'),
	(138, 'Criminal Sale of Weapon Class D', 'The act of selling a Class D firearm without licensing', 'Felony', 'yellow', 65, 35000, 'offenses against public safety'),
	(139, 'Criminal Use of Weapon', 'The Unlawful use of a firearm, knife, or other dangerous weapon to commit or attempt to commit a crime.', 'Misdemeanor', 'yellow', 10, 450, 'offenses against public safety'),
	(140, 'Possession of Illegal Firearm Modifications', 'he Unlawful possession of devices or alterations that modify a firearm to enhance its capabilities beyond what is legally allowed. (Suppressors and Extended Magazines)', 'Misdemeanor', 'green', 25, 4000, 'offenses against public safety'),
	(141, 'Weapon Trafficking', 'The illegal trade, sale, transport, piling or distribution of firearms, ammunition, or other weapons.', 'Felony', 'red', 0, 0, 'offenses against public safety'),
	(142, 'Brandishing a Weapon', 'The Unlawful Act of displaying, waving, or pointing a weapon in a threatening, aggressive, or intimidating manner. Often with the intent to provoke fear.', 'Misdemeanor', 'yellow', 15, 500, 'offenses against public safety'),
	(143, 'Insurrection', 'A Violent uprising or rebellion against an established government or authority with the intent to overthrow, disrupt, or challenge its rule. Typically involves acts of force, resistance, or obstruction against government officials, institutions, or laws.', 'Felony', 'red', 0, 0, 'offenses against public safety'),
	(144, 'Flying into Restricted Airspace', 'Piloting and aircraft into airspace that is governmentally controlled', 'Felony', 'green', 20, 1500, 'offenses against public safety'),
	(145, 'Jaywalking', 'crossing a roadway in a manner that is hazardous to motor vehicles', 'Infraction', 'green', 0, 150, 'offenses against public safety'),
	(146, 'Criminal Use of Explosives', 'The Unlawful use or detonation of explosive materials or devices, such as dynamite, thermite, C4, or homemade explosive devices, to cause destruction, harm, or fear.', 'Felony', 'yellow', 30, 12500, 'offenses against public safety'),
	(147, 'Possession of a Government-Issued Weapon', 'The illegal Possession of a firearm or weapon that has been issued by a government entity. This must be identified as a Government-Issued Weapon for example Glock or HK416', 'Felony', 'red', 175, 35000, 'offenses against public safety'),
	(148, 'Possession of Government-Issued Equipment', 'Possession of Government-Issued equipment (Stackable per individual item). This includes PD Tasers.', 'Felony', 'yellow', 10, 3000, 'offenses against public safety'),
	(149, 'Improper use of a Firearm', 'The Unlawful or unsafe handling, discharge, or application of a firearm in a manner that endangers others, violates the law, or is inconsistent with the safe and responsible firearm practices.', 'Felony', 'yellow', 15, 3500, 'offenses against public safety'),
	(150, 'Improper use of a Firearms License', 'Failure to declare a lawfully-held firearm as stolen. The original owner of the firearm is also liable as an accessory charge to all crimes committed with their weapon.', 'Felony', 'yellow', 15, 3500, 'offenses against public safety'),
	(151, 'Stockpiling of Firearms', 'Any Person who is found to have two (2) or more Class 1, Class 2, Class 3 Firearms, Molotov Cocktails, and/or Rocket Propelled Grenade Launchers stored in one location. This charge will be utilized in addition to the possession charges if a Defendant is charged as being present when the guns are found. If the guns are found by way of search warrant or hot pursuit in a physical storage location, then the charges will be applied constructively, both to the person present and to the property owner.', 'Misdemeanour', 'yellow', 50, 15000, 'offenses against public safety'),
	(152, 'Manufacture of Explosives', 'The illegal production or creation of explosive materials or devices, such as dynamite, thermite, C4 or other explosive compounds without proper authorization.', 'Felony', 'red', 80, 40000, 'offenses against public safety'),
	(153, 'Driving While Intoxicated', 'Operating a vehicle impaired by alcohol, drugs, or other substances to the point where the drivers ability to operate the vehicle safely is compromised.', 'Misdemeanor', 'green', 5, 300, 'offenses involving the operation of a vehicle'),
	(154, 'Evading', 'The Act of deliberately attempting to escape or flee from law enforcement officers who are attempting to stop or pursue a person. This can involve running on foot, driving away in a vehicle, or using other means to avoid arrest or questioning.', 'Misdemeanor', 'green', 5, 400, 'offenses involving the operation of a vehicle'),
	(155, 'Reckless Evading', 'The Act of intentionally fleeing from law enforcement officers in a manner that demonstrates a disregard for the safety of others. This often involves high-speed chases, running red lights, driving on the wrong side of the road, engaging in other dangerous maneuvers whilst attempting to escape. ', 'Felony', 'yellow', 10, 800, 'offenses involving the operation of a vehicle'),
	(156, 'DELETE', 'The offense of not giving the right of way to an emergency vehicle, such as an ambulance, fire truck, or police vehicle, that is using its siren or lights while responding to an emergency.', 'Misdemeanor', 'green', 10, 6500, 'offenses involving the operation of a vehicle'),
	(157, 'Failure to Obey Traffic Control Device', 'Failing to stop at a stop sign or failing to come to a complete stop at a red light (red lights treated as stop signs; right-of-way must be yielded before proceeding)', 'Infraction', 'green', 0, 1200, 'offenses involving the operation of a vehicle'),
	(158, 'Nonfunctional Vehicle', 'A Vehicle that is not working condition and cannot be operated safely or legally on the road. This can include vehicles that are smoking, have mechanical issues or missing essential parts such as tires, windscreen. ', 'Infraction', 'green', 0, 75, 'offenses involving the operation of a vehicle'),
	(159, 'Negligent Driving', 'Operating a vehicle in a careless or inattentive manner that endangers others or their property, but without the intent to cause harm.', 'Infraction', 'green', 0, 300, 'offenses involving the operation of a vehicle'),
	(160, 'Reckless Driving', 'Operating a vehicle in a manner that shows a willful disregard for the safety of people or property. Often involves actions such as speeding excessively, running red lights, aggressive lane changes.', 'Misdemeanor', 'yellow', 10, 750, 'offenses involving the operation of a vehicle'),
	(161, 'Third Degree Speeding', 'Speeding 15 over the limit', 'Infraction', 'green', 0, 225, 'offenses involving the operation of a vehicle'),
	(162, 'Second Degree Speeding', 'Speeding 35 over the limit', 'Infraction', 'green', 5, 450, 'offenses involving the operation of a vehicle'),
	(163, 'First Degree Speeding', 'Speeding 50 over the limit', 'Infraction', 'green', 10, 750, 'offenses involving the operation of a vehicle'),
	(164, 'Unlicensed Operation of Vehicle', 'Driving a vehicle without a valid driverÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s vehicle or with a suspended or revoked license.', 'Infraction', 'green', 0, 500, 'offenses involving the operation of a vehicle'),
	(165, 'Illegal U-Turn', 'Making a U-turn (a complete turn to go in the opposite direction) at a location where it is prohibited by traffic laws.', 'Infraction', 'green', 0, 75, 'offenses involving the operation of a vehicle'),
	(166, 'Illegal Passing', 'The Act of overtaking and passing another vehicle in a manner that violates traffic laws. This can include passing on the wrong side of the road.', 'Infraction', 'green', 0, 300, 'offenses involving the operation of a vehicle'),
	(167, 'Failure to Maintain Lane', 'The act of not staying within designated lanes of a roadway while driving. This can include swearing, drifting, or crossing lanes.', 'Infraction', 'green', 0, 300, 'offenses involving the operation of a vehicle'),
	(168, 'Illegal Turn', 'Making a turn in violation of traffic laws or regulations.', 'Infraction', 'green', 0, 150, 'offenses involving the operation of a vehicle'),
	(169, 'Failure to Stop', 'The Act of not coming to a complete stop at a stop sign, red light, or when required by law.', 'Infraction', 'green', 0, 600, 'offenses involving the operation of a vehicle'),
	(170, 'Unauthorized Parking', 'Parking a vehicle in a space or area where it is not allowed by law or local regulations.', 'Infraction', 'green', 0, 300, 'offenses involving the operation of a vehicle'),
	(171, 'Hit and Run', 'Leaving the scene of an accident without stopping to provide identification, assist the injured, or report the incident to law enforcement.', 'Misdemeanor', 'green', 10, 500, 'offenses involving the operation of a vehicle'),
	(172, 'Driving without Headlights or Signals', 'Operating a vehicle with no functional lights', 'Infraction', 'green', 0, 300, 'offenses involving the operation of a vehicle'),
	(173, 'Street Racing', 'The illegal practice of racing vehicles on public or highways, often at high speeds.', 'Felony', 'green', 20, 1500, 'offenses involving the operation of a vehicle'),
	(174, 'Piloting without Proper Licensing', 'The Act of operating an aircraft without the required pilotÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s license or certification. This includes a plane, helicopter or other aircrafts.', 'Felony', 'yellow', 20, 1500, 'offenses involving the operation of a vehicle'),
	(175, 'Unlawful Use of a Motor Vehicle', 'The Unauthorized or illegal operation, use, or possession of a vehicle. This can include actions such as driving a stolen vehicle, using a vehicle without the ownerÃÆÃÂ¢ÃÂ¢Ã¢â¬Å¡ÃÂ¬ÃÂ¢Ã¢â¬Å¾ÃÂ¢s permission, or operating a vehicle in violation of the law. (e.g driving with a suspended license)', 'Misdemeanor', 'green', 10, 750, 'offenses involving the operation of a vehicle'),
	(176, 'Hunting in Restricted Areas', 'The Act of pursuing, capturing, or killing wildlife in locations where hunting is prohibited or regulated by law or policy.', 'Infraction', 'green', 0, 450, 'offenses involving the well-being of wildlife'),
	(177, 'Unlicensed Hunting', 'The Act of hunting wildlife without possessing the necessary legal authorization or permits required by state.', 'Infraction', 'green', 0, 450, 'offenses involving the well-being of wildlife'),
	(178, 'Animal Cruelty', 'The intentional infliction of harm, suffering, or neglect upon animals by humans. This can include acts that cause physical injury, distress, as well as the failure to provide necessary care and humane treatment.', 'Misdemeanor', 'green', 10, 450, 'offenses involving the well-being of wildlife'),
	(179, 'Hunting with a Non-Hunting Weapon', 'The Act of pursuing, capturing, or killing wildlife using equipment or tools that are not designed, approved, or legally permitted for hunting purposes.', 'Misdemeanor', 'green', 10, 750, 'offenses involving the well-being of wildlife'),
	(180, 'Hunting outside of hunting hours', 'Harvesting animals outside of specified time to do so', 'Infraction', 'green', 0, 750, 'offenses involving the well-being of wildlife'),
	(181, 'Overhunting', 'The excessive hunting of wildlife (Greater than 10)', 'Misdemeanor', 'green', 10, 1000, 'offenses involving the well-being of wildlife'),
	(182, 'Poaching', 'The illegal hunting, capturing, or killing of wildlife classified as protected species. Wild Deer, Wild Boar and Wild Rabbit are authorized and any other animal is considered restricted or protected', 'Felony', 'red', 20, 1250, 'offenses involving the well-being of wildlife'),
	(183, 'Store Robbery', 'Robbing commercial establishment', 'DELETE', 'red', 25, 8000, 'major robberies'),
	(184, 'Unlawful Possession of a Firearm', 'Displaying firearm in threatening manner.', 'Misdemeanor', 'red', 12, 8000, 'firearms'),
	(185, 'Brandishing a Firearm', 'Displaying or pointing a firearm in a threatening manner without lawful cause', 'Misdemeanor', 'yellow', 15, 9000, 'firearms'),
	(186, 'Discharging a Firearm in City Limits', 'Firing a weapon within city limits without lawful justification', 'Felony', 'red', 25, 14000, 'firearms'),
	(187, 'Reckless Discharge of a Firearm', 'Firing a weapon in a negligent manner that endangers others', 'Felony', 'red', 25, 18000, 'firearms'),
	(188, 'Possession of a Prohibited Firearm', 'Possessing a banned or restricted-class weapon without authorization', 'Felony', 'red', 20, 15000, 'firearms'),
	(189, 'Possession of a Firearm During Commission of a Crime', 'Having a firearm while committing another criminal offence', 'Felony', 'red', 30, 20000, 'firearms'),
	(190, 'Use of a Firearm in the Commission of a Felony', 'Actively using or firing a firearm during a serious criminal offence', 'Felony', 'red', 35, 25000, 'firearms'),
	(191, 'Possession of an Altered or Serial-Removed Firearm', 'Owning/Possession a firearm with a removed or modified serial number', 'Felony', 'red', 30, 22000, 'firearms'),
	(192, 'Trafficking Firearms', 'Selling or distributing firearms illegally', 'Felony', 'red', 40, 30000, 'firearms'),
	(193, 'Theft of an Emergency Vehicle', 'Unlawfully taking or operating a marked or unmarked Law Enforcement, EMS, Fire Department vehicle, or emergency helicopter without authorization', 'Felony', 'red', 40, 25000, 'government & emergency vehicle offenses'),
	(194, 'Failure to Yield to Emergency Vehicle', 'Not moving over or stopping for active lights and sirens', 'Misdemeanor', 'yellow', 15, 6500, 'government & emergency vehicle offenses'),
	(195, 'Tampering with Government Property', 'Damaging, disabling, or interfering with government or emergency equipment or vehicles', 'Felony', 'red', 25, 15000, 'government & emergency vehicle offenses'),
	(196, 'Obstruction of Emergency Operations', 'Interfering with Law Enforcement, Fire, or EMS during active emergency response', 'Misdemeanor', 'yellow', 12, 8000, 'government & emergency vehicle offenses'),
	(197, 'Grand Theft of Government Property', 'Stealing high-value government-owned assets or equipment', 'Felony', 'red', 35, 22000, 'government & emergency vehicle offenses'),
	(198, 'Felony Evading Causing Serious Injury', 'Fleeing law enforcement resulting in serious injury to another person', 'Felony', 'red', 45, 25000, 'high-severity offenses'),
	(199, 'Operating a Business Without a Valid License', 'Operating or advertising a business without an approved and active city license', 'Misdemeanor', 'yellow', 20, 15000, 'business offenses'),
	(200, 'Failure to Renew Business License', 'Allowing a business license to expire beyond the required renewal period', 'Infraction', 'green', 20, 10000, 'business offenses'),
	(201, 'Abuse of Public Office', 'Using an official position to gain personal benefit or harm another unlawfully', 'Felony', 'red', 35, 24500, 'public trust & authority offenses'),
	(202, 'Tampering with Public Records', 'Altering, destroying, or falsifying government documents or databases', 'Felony', 'red', 40, 28000, 'public trust & authority offenses'),
	(203, 'Unauthorized Disclosure of Confidential Information', 'Releasing protected government or investigative information without authorization', 'Misdemeanor', 'yellow', 15, 12000, 'public trust & authority offenses'),
	(204, 'Impersonation of a Public Official', 'Falsely presenting oneself as a government employee or officer', 'Felony', 'red', 30, 18000, 'public trust & authority offenses'),
	(205, 'Hunting Without a Valid Firearms License', 'Any individual found hunting wildlife without being in possession of a valid firearms license while carrying or using a hunting weapon.', 'Misdemeanor', 'yellow', 15, 1500, 'wildlife & hunting regulations'),
	(206, 'Hunting Without Required Safety Clothing', 'Failure to wear hunter orange or visible safety clothing while hunting.', 'Infraction', 'green', 15, 750, 'wildlife & hunting regulations'),
	(207, 'Reckless or Inaccurate Hunting (Unsafe Shooting)', 'Discharging a firearm while hunting in a reckless or careless manner that shows lack of target accuracy, failure to properly identify the target, or firing without a clear shot. Hunters must ensure they are shooting safely and accurately at intended wildlife.', 'Misdemeanor', 'yellow', 15, 1500, 'wildlife & hunting regulations');
