INSERT INTO `mdt_reports` (`id`, `leadOfficer`, `title`, `description`, `summary`, `leadOfficerName`, `posted`, `reportType`, `offlineSummary`) VALUES
	(7, '89909', 'Car Jacking', 'New Description', '', 'Josh Sims', 1772508233, 'incident', '{"content":[{"content":[{"text":"103 Josh Sims was refilling his car when he got a fight in progess call just by the gas staion on little soal soon after he got a vehicle theft form the same place he seen 2 indiviashuals get into the vehicle and throw someone out past that they lead 103 Josh Sims on a chase soon after the chase has started 101 Todd Williams joined in 103 and 101 made it to the high way just befor the air port befor they got on foot and started fleeing thats where both 101 and 103 lost eyes vehicle was surched and the onlt thing found was one set of fingerprints unknown names at this time","type":"text"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"101 | Todd Williams || Date: 2026-03-02","marks":[{"type":"bold"}]},{"type":"hardBreak"},{"text":"Type: FINGERPRINT | Date: 03/02/26 @ 10:13 | Location: Dutch London St | Plate: 81GMZ095 | Fingerprint: 07Q5ZQ5Q763VMW4","type":"text"},{"type":"hardBreak"},{"type":"hardBreak"},{"text":"Evidence Locker: ID#7","type":"text"}],"type":"paragraph"}],"type":"doc"}'),
	(8, '31426', 'Allison James', 'Reckless Driving & Evading', '', 'Todd Williams', 1772510008, 'incident', '{"content":[{"content":[{"type":"text","text":"101 | Todd Williams || Date: 2026-03-02","marks":[{"attrs":{"color":"#ed0707"},"type":"textStyle"},{"type":"bold"}]},{"type":"hardBreak"},{"text":"101 Todd Williams was parked at the intersection of Vespucci Boulevard East and Calais Avenue when he observed a white van run a red light and sharply cut the corner from left to right, nearly entering the westbound lanes of Vespucci Boulevard. The vehicle then proceeded to run a second red light without stopping.","type":"text"},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"text":"At that time, 101 activated emergency lights and sirens in an attempt to conduct a traffic stop. The vehicle failed to yield and continued eastbound on Vespucci Boulevard, passing MRPD. The driver began stopping and going at red lights but still failed to properly pull over for the emergency vehicle.","type":"text"},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"text":"The vehicle eventually stopped at what appeared to be a job site in Mirror Park on the northeast side. The driver was given lawful commands to stop, put her hands up, and face away. She failed to comply. 103 Josh Sims attempted to detain her by tackling, but was unable to secure cuffs. This occurred three additional times before she re-entered her vehicle and drove back toward her work building.","type":"text"},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"text":"She continued to fail to comply, at which point officers de-escalated the situation and obtained her identification. It was determined she did not possess a valid driverÃ¢â¬â¢s license and was operating on a permit. She was issued citations accordingly.","type":"text"},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"text":"All SASP members cleared the area.","type":"text"}],"type":"paragraph"}],"type":"doc"}'),
	(9, '31426', 'Unknown Person', 'Theft of an Emergency Vehicle & Evadng', '', 'Todd Williams', 1772589596, 'incident', '{"content":[{"content":[{"text":"101 | Todd Williams || Date: 2026-03-02","type":"text","marks":[{"type":"textStyle","attrs":{"color":"#ff0a0a"}},{"type":"bold"}]}],"type":"paragraph"},{"content":[{"type":"text","text":"101 Todd Williams and 108 Chad were at MRPD conducting a walkthrough of the station when we received a call regarding a stolen vehicle in the area of Vespucci PD and Burger Shot. Upon arrival in the area, SASP units observed a stolen LSPD motorcycle being operated by a white male with blue hair wearing a blue sweatshirt. Officers activated lights and sirens, at which point the suspect immediately fled."},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"type":"text","text":"A vehicle pursuit was initiated and continued until the suspect became stuck. The suspect then fled on foot near Del Perro Freeway and North Rockford Drive. SASP members deployed a taser and attempted to take the suspect into custody; however. The suspect entered another vehicle and fled the area. Officers maintained pursuit but eventually lost visual contact. A search of the area was conducted with negative results."}],"type":"paragraph"},{"content":[{"type":"text","text":"One fingerprint was recovered from the stolen motorcycle."},{"type":"hardBreak"}],"type":"paragraph"},{"content":[{"text":"Evidence Locker:","type":"text","marks":[{"type":"bold"}]},{"type":"text","text":" ID #8"},{"type":"hardBreak"},{"type":"text","text":"Type: FINGERPRINT | Date: 03/03/26 @ 08:56 | Location: Del Perro Fwy | Plate: 40SLO874 | Fingerprint: 93PN6S3IN365TY2"}],"type":"paragraph"}],"type":"doc"}'),
	(10, '89909', 'Tony Walker', 'Fleeing', '', 'Josh Sims', 1772673115, 'incident', '{"type":"doc","content":[{"type":"paragraph","content":[{"text":"On patrol, Officers 101 ","type":"text"},{"marks":[{"type":"bold"}],"text":"Todd Williams","type":"text"},{"text":", 102 ","type":"text"},{"marks":[{"type":"bold"}],"text":"Josh Sims","type":"text"},{"text":", and 108 ","type":"text"},{"marks":[{"type":"bold"}],"text":"Chad Cooper","type":"text"},{"text":" were monitoring multiple reckless driving calls originating from speed cameras in the area. Due to a high number of complaints coming from ","type":"text"},{"marks":[{"type":"bold"}],"text":"Greenwich Parkway near the dealership","type":"text"},{"text":", the officers positioned themselves there and began running radar.","type":"text"}]},{"type":"paragraph","content":[{"text":"While stationary, the officers observed a black two-door sports car traveling at a high rate of speed, too fast to obtain a radar reading. A traffic stop was initiated on ","type":"text"},{"marks":[{"type":"bold"}],"text":"Greenwich Way","type":"text"},{"text":".","type":"text"}]},{"type":"paragraph","content":[{"text":"Officer 102 exited the patrol vehicle and approached the driver. As soon as Officer 102 reached the driverÃ¢â¬â¢s window, the vehicle fled the scene, heading toward the airport. The suspect turned onto ","type":"text"},{"marks":[{"type":"bold"}],"text":"Exceptionalists Way","type":"text"},{"text":" and proceeded up a dirt hill. A pursuit was initiated, with speeds exceeding 120 MPH.","type":"text"}]},{"type":"paragraph","content":[{"text":"The pursuit continued until ","type":"text"},{"marks":[{"type":"bold"}],"text":"Innocence Boulevard","type":"text"},{"text":", where the suspect vehicle rolled over and crashed. The driver was removed from the vehicle, placed in handcuffs, and read his Miranda rights.","type":"text"}]},{"type":"paragraph","content":[{"text":"The suspect was transported to the PD and processed for:","type":"text"}]},{"type":"bulletList","content":[{"type":"listItem","content":[{"type":"paragraph","content":[{"text":"Reckless Evading","type":"text"}]}]},{"type":"listItem","content":[{"type":"paragraph","content":[{"text":"Grand Theft of a Vehicle","type":"text"}]}]}]},{"type":"paragraph"}]}'),
	(11, '89909', 'Baja Boom', 'Wreckless evading', '', 'Josh Sims', 1772848482, 'incident', '{"content":[{"content":[{"text":"Officer: 102 Josh Sims","type":"text"},{"type":"hardBreak"},{"text":"Location: Beach Parking Lot","type":"text"},{"type":"hardBreak"},{"text":"Incident: Stolen Vehicle Recovery / Suspect Arrest","type":"text"}],"type":"paragraph"},{"content":[{"text":"While responding to a call regarding a stolen vehicle, Officer 102 Josh Sims arrived at the beach parking lot and located a vehicle matching the stolen license plate information. When Officer Sims attempted a traffic stop, the suspect fled the scene, initiating a pursuit that lasted approximately five minutes.","type":"text"}],"type":"paragraph"},{"content":[{"text":"During the pursuit, the suspect drove recklessly, including driving on the sidewalk and swerving across the roadway. The suspect eventually came to a stop, at which point Officer Sims removed the driver from the vehicle and placed him in handcuffs.","type":"text"}],"type":"paragraph"},{"content":[{"text":"Due to being the only officer on duty at the time, Officer Sims remained on scene longer than usual to secure the area and process the vehicle. Once returned to the station, the suspect was identified as Mr. Baja Boom. Appropriate fines were issued, and the suspect served time in the holding cell.","type":"text"}],"type":"paragraph"}],"type":"doc"}'),
	(12, '89909', 'Unknown Person', 'stolen vehicle recovered ', 'AQSI4vqcDAABAQdkZWZhdWx0AQACh4ji+pwMAAMJcGFyYWdyYXBoR4ji+pwMAAMJcGFyYWdyYXBoAYji+pwMAQAD', 'Josh Sims', 1772853230, 'incident', '{"content":[{"content":[{"text":"101 Todd Williams and 102 Josh Sims received a report of a stolen vehicle near the mines. 102 drove down the Senora Freeway while 101 took Route 13 to search for the vehicle. As 102 neared Bolingbroke, he looked for the stolen car coming down the road. 102 then spotted a vehicle traveling at a high rate of speed, but could not clock the speed since it was too far for radar. The vehicle was heading into the city on the Santa Fe Freeway. 102 attempted to catch up and saw the vehicle pull over on the northbound Los Santos Freeway. 102 waited for backup from 101 before making contact. Once 101 arrived, 102 approached and found the driver was compliant throughout. 102 asked questions about how the vehicle was obtained; the driver claimed it was his friend\'s car and that he was borrowing it. When the plates were checked, nothing came up. 102 asked again where the vehicle came from. The driver was unsure but repeated that it belonged to his friend. After discussing the situation, 101 and 102 decided to let the suspect call for a ride home and impounded the vehicle, as it had been reported as stolen.","type":"text"}],"type":"paragraph"}],"type":"doc"}'),
	(15, '71308', 'Suspect Name', 'Charge', 'AgSW7I+LCAAHAQdkZWZhdWx0AwlwYXJhZ3JhcGgHAJbsj4sIAAYEAJbsj4sIAQdUaGlzIGlzgZbsj4sICA4Kj6qAkgQAgZbsj4sIFgGEj6qAkgQAAiB0gY+qgJIEAgSEj6qAkgQGAmhlgY+qgJIECAGEj6qAkgQJBCByZXCBj6qAkgQNAoSPqoCSBA8Db3J0gY+qgJIEEgGEj6qAkgQTCCBhcmVhLsKgApbsj4sIAQkOj6qAkgQFAAEDBAkBDgITAQ==', 'Stephen Johnson', 1773049768, 'incident', NULL);
