INSERT INTO `phone_services_messages` (`id`, `channel_id`, `sender`, `message`, `x_pos`, `y_pos`, `timestamp`) VALUES
	(1, 1, '3052512167', 'will you deliver?', -1579, -243, '2026-04-06 01:18:47'),
	(2, 2, '3051734328', 'Hello, SASP here. Weâd like to place a pickup order for 40x Surf & Turf meals and 40x cups of Sprunk (or the highest-calorie non-alcoholic drinks available). Please confirm availability and pickup time. Thank you.', -714, -912, '2026-04-07 19:53:39'),
	(3, 3, '6697752820', 'Hi, can I purchase a car?', 147, -3023, '2026-04-08 02:51:01'),
	(4, 3, '6503356154', 'Yes ', NULL, NULL, '2026-04-08 02:55:25'),
	(5, 3, '6503356154', 'Lenny can do it. ', NULL, NULL, '2026-04-08 02:55:58'),
	(6, 3, '6697752820', '<!SENT-LOCATION-X=-954.73Y=-2056.95!>', -955, -2057, '2026-04-08 03:02:29'),
	(7, 4, '4155645069', 'I have a quick question do you guys fiance and if so what is the required down payment', -912, -2043, '2026-04-12 01:46:27'),
	(8, 4, '6697752820', 'We prefer not to, but if you can pay 70% down to cover the oder cost, we can finance', NULL, NULL, '2026-04-12 01:49:24'),
	(9, 4, '4155645069', 'okay if you guys prefer not to I can wait tell I have the full amount ', -301, -988, '2026-04-12 01:50:01'),
	(10, 4, '6697752820', 'I definitely prefer not to do it often, but once in a while isn\'t an issue', NULL, NULL, '2026-04-12 01:50:36'),
	(11, 4, '4155645069', 'okay gotcha let me do somethinking ', -365, -134, '2026-04-12 01:51:33'),
	(12, 4, '6697752820', 'Just let me know if I can be of assistance', NULL, NULL, '2026-04-12 01:54:29'),
	(13, 5, '4155645069', 'any chance you are able to open up the shop I need a repair', 448, -974, '2026-04-14 23:48:44'),
	(14, 5, '6693528112', 'im open', NULL, NULL, '2026-04-14 23:50:04'),
	(15, 5, '4155645069', 'im here I dont see anyone', 138, -3032, '2026-04-14 23:52:22'),
	(16, 4, '4155645069', 'hey any chance your around the dealership?', 434, -992, '2026-04-16 02:12:22'),
	(17, 6, '3051734328', 'hey', -321, -121, '2026-04-24 17:20:21'),
	(18, 7, '6507430647', 'can you meet me at PD I need a wepons license', 155, -1033, '2026-04-25 00:25:13'),
	(19, 7, '3051734328', 'An officer is en route to your location.', NULL, NULL, '2026-04-25 00:28:53'),
	(20, 7, '6507430647', 'the gun shop said I dont have a license', -1083, -254, '2026-04-25 00:43:36'),
	(21, 7, '3051734328', 'i will need to re grant it! Is there somewhere we can meet', NULL, NULL, '2026-04-25 01:06:24'),
	(22, 7, '6507430647', 'why do we half to meet and you cant do it fomr that computer of yours ', 184, -1425, '2026-04-25 01:33:51'),
	(23, 7, '3051734328', 'that what was done but failed to reg, sue to this we can meet and i will grant it another way', NULL, NULL, '2026-04-25 01:35:38'),
	(24, 8, '3051734328', 'SASP IS LOOKING TO PLACE A ORDER! Are you able to feed the PD?', 437, -995, '2026-04-25 21:29:43'),
