INSERT INTO `vx_mdt_charges` (`id`, `category_id`, `title`, `description`, `code`, `type`, `recommended_fine`, `recommended_time`, `points`, `stackable`, `created_at`) VALUES
	(147, 4, 'Speeding (15 MPH Over)', 'Operating a motor vehicle at a speed exceeding the posted speed limit by up to fifteen miles per hour.', 'PC600', 'infraction', 1200, 0, 0, 0, '2026-03-18 01:46:51'),
	(148, 4, 'Speeding (30 MPH Over)', 'Driving significantly above the posted speed limit, increasing the risk of collision and loss of vehicle control.', 'PC601', 'infraction', 1500, 0, 1, 0, '2026-03-18 01:51:15'),
	(149, 4, 'Speeding (31+ MPH Over)', 'Driving at an extremely dangerous speed exceeding the limit by more than thirty miles per hour.', 'PC602', 'misdemeanor', 4500, 20, 2, 1, '2026-03-18 01:53:02'),
	(150, 4, 'Disregarding a Traffic Control Device', 'The act of failing to obey any posted or visible traffic control signal, including running a red light, ignoring a stop sign, or disobeying directional or regulatory roadway signs, in violation of stop-and-go traffic laws.', 'PC603', 'infraction', 1250, 0, 1, 1, '2026-03-18 01:56:18'),
	(151, 4, 'Blocking Intersection', 'Stopping or remaining in an intersection in a manner that blocks traffic flow.', 'PC604', 'infraction', 1000, 0, 0, 1, '2026-03-18 01:57:13'),
	(152, 4, 'Illegal Parking in Fire Lane', 'Parking a vehicle in designated fire lanes or emergency access areas. (MARKED WITH RED CURB)', 'PC605', 'infraction', 5000, 0, 0, 1, '2026-03-18 01:59:03'),
	(153, 4, 'Illegal Window Tint', 'Operating a vehicle with window tint darker than legally permitted.', 'PC606', 'infraction', 900, 0, 1, 1, '2026-03-18 02:00:50'),
	(154, 4, 'Driving Without License', 'Operating a motor vehicle without a valid driver\'s license.', 'PC607', 'misdemeanor', 5000, 0, 5, 0, '2026-03-18 02:01:55'),
	(155, 4, 'Driving With Suspended License', 'Operating a motor vehicle while your license is suspended or revoked.', 'PC608', 'misdemeanor', 5500, 18, 10, 0, '2026-03-18 02:03:41'),
	(156, 4, 'Reckless Driving', 'Driving with willful disregard for the safety of persons or property.', 'PC609', 'misdemeanor', 5000, 0, 3, 0, '2026-03-18 02:04:24'),
	(157, 4, 'Aggressive Driving', 'Driving in a hostile or dangerous manner such as tailgating, brake-checking, or weaving through traffic.', 'PC610', 'misdemeanor', 5500, 20, 4, 0, '2026-03-18 02:05:05'),
	(158, 4, 'Street Racing', 'Participating in illegal racing or speed competitions on public roads.', 'PC611', 'felony', 12000, 35, 8, 0, '2026-03-18 02:06:53'),
	(159, 4, 'Organizing Street Race', 'Organizing or promoting illegal street racing events.', 'PC612', 'felony', 13000, 45, 10, 0, '2026-03-18 02:07:42'),
	(160, 4, 'Reckless Endangerment with Vehicle', 'Operating a vehicle in a manner that places others at significant risk of injury.', 'PC613', 'felony', 12000, 25, 12, 0, '2026-03-18 02:09:32'),
	(161, 4, 'Evading Police', 'Fleeing from a peace officer after being signaled to stop.', 'PC614', 'misdemeanor', 11000, 26, 5, 0, '2026-03-18 02:10:43'),
	(162, 4, 'Felony Evading Police', 'Evading police while driving recklessly or endangering others.', 'PC615', 'felony', 13500, 30, 12, 0, '2026-03-18 02:11:53'),
	(163, 4, 'Evading Police Resulting in Injury', 'Fleeing law enforcement and causing injury to another person.', 'PC616', 'felony', 16000, 45, 14, 0, '2026-03-18 02:12:59'),
	(164, 4, 'Evading Police Resulting in Death', 'Fleeing law enforcement and causing a fatal collision.', 'PC617', 'felony', 30000, 200, 30, 0, '2026-03-18 02:21:04'),
	(165, 4, 'Hit and Run (Property Damage)', 'Leaving the scene of a collision involving property damage without providing information.', 'PC618', 'misdemeanor', 6000, 16, 3, 0, '2026-03-18 02:21:51'),
	(166, 4, 'Hit and Run (Injury)', 'Leaving the scene of an accident involving injury to another person.', 'PC619', 'felony', 12000, 20, 4, 0, '2026-03-18 02:22:43'),
	(167, 4, 'Hit and Run (Fatal)', 'Leaving the scene of a collision that resulted in death.', 'PC620', 'felony', 30000, 210, 32, 0, '2026-03-18 02:27:20'),
	(168, 4, 'Driving Under the Influence (DUI)', 'Operating a vehicle while impaired by alcohol or drugs.', 'PC621', 'misdemeanor', 7000, 30, 0, 0, '2026-03-18 02:28:26'),
	(169, 4, 'Illegal Vehicle Modification (WORKING)', 'Operating a vehicle modified in violation of vehicle safety regulations.', 'PC622', 'infraction', 1200, 0, 1, 1, '2026-03-18 02:30:49'),
	(170, 4, 'Illegal Nitro Use on Public Roads', 'Using nitrous or racing modifications on public roadways.', 'PC623', 'misdemeanor', 4500, 0, 4, 1, '2026-03-18 02:32:37'),
	(171, 4, 'Illegal Off-Road Driving', 'Driving vehicles in areas not designated for road travel.', 'PC624', 'infraction', 1000, 0, 1, 1, '2026-03-18 02:34:34'),
	(172, 4, 'Vehicle Assault', 'Intentionally using a motor vehicle as a weapon against another person.', 'PC625', 'misdemeanor', 10000, 25, 8, 1, '2026-03-18 02:38:10'),
	(173, 4, 'Attempted Vehicular Murder', 'Attempting to kill another individual using a vehicle.', 'PC626', 'felony', 18000, 50, 18, 0, '2026-03-18 02:39:00'),
	(174, 4, 'Vehicular Manslaughter', 'Causing the death of another individual through reckless driving.', 'PC627', 'felony', 35000, 215, 40, 0, '2026-03-18 02:40:24'),
	(175, 4, 'Failure to Yield to Emergency Vehicle', 'Failing to move aside or stop for police, fire, or EMS vehicles with lights and sirens activated.', 'PC628', 'infraction', 6500, 0, 6, 1, '2026-03-18 02:41:13'),
	(176, 4, 'Interfering with Emergency Vehicle', 'Intentionally blocking or interfering with emergency response vehicles.', 'PC629', 'misdemeanor', 7000, 20, 8, 1, '2026-03-18 02:42:11'),
	(177, 4, 'Driving Wrong Way', 'Driving against the designated direction of travel on a roadway.', 'PC630', 'misdemeanor', 7000, 18, 4, 1, '2026-03-18 02:42:59'),
	(178, 4, 'Operating Unsafe Vehicle', 'Driving a vehicle with severe mechanical issues posing danger to others.', 'PC631', 'infraction', 4500, 0, 1, 1, '2026-03-18 02:44:02'),
	(179, 4, 'Driving While Using Mobile Device', 'Using handheld mobile devices while operating a vehicle.', 'PC632', 'infraction', 1750, 0, 1, 1, '2026-03-18 02:45:18'),
	(180, 6, 'Disturbing the Peace', 'Engaging in loud, disruptive, or disorderly conduct in a public area that interferes with the peace or comfort of others nearby. Examples include yelling, fighting, blasting loud music, or creating disturbances that attract police complaints.', 'PC100', 'infraction', 800, 0, 0, 1, '2026-03-18 02:47:00'),
	(181, 6, 'Loitering', 'Remaining in a public or private location without legitimate purpose while interfering with normal public activity or causing concern of potential criminal activity.', 'PC101', 'infraction', 900, 0, 0, 1, '2026-03-18 02:47:39'),
	(182, 6, 'Illegal Parking', 'Parking a vehicle in restricted areas such as fire lanes, sidewalks, intersections, or locations that obstruct traffic or emergency access.', 'PC102', 'infraction', 1200, 0, 0, 1, '2026-03-18 02:48:23'),
	(183, 6, 'Littering', 'Improperly disposing of trash, debris, or waste materials in public spaces instead of designated disposal containers.', 'PC103', 'infraction', 950, 0, 0, 1, '2026-03-18 02:49:03'),
	(184, 6, 'Disorderly Conduct (A)', 'Engaging in disruptive or aggressive behavior that causes alarm, annoyance, or disturbance to others.', 'PC104 (A)', 'misdemeanor', 4500, 10, 0, 1, '2026-03-18 02:50:09'),
	(186, 6, 'Disorderly Conduct (B)', 'Engaging in minor disruptive or disorderly behavior that causes annoyance or disturbance to others, without escalating to violence or significant public safety risk.', 'PC104 (B)', 'infraction', 4000, 0, 0, 1, '2026-03-18 02:51:58'),
	(187, 6, 'Failure to Obey Lawful Order', 'Refusing or failing to comply with lawful instructions issued by a peace officer during an investigation or incident.', 'PC107', 'misdemeanor', 5500, 0, 0, 1, '2026-03-19 00:28:30'),
	(188, 6, 'Refusal to Identify', 'Refusing to provide identifying information to a peace officer during lawful detention.', 'PC105', 'infraction', 6500, 0, 0, 1, '2026-03-19 00:29:24'),
	(189, 6, 'Harassment', 'Repeatedly threatening, intimidating, or disturbing another individual in a way that causes distress.', 'PC106', 'misdemeanor', 6000, 25, 0, 1, '2026-03-19 00:30:01'),
	(190, 1, 'Simple Assault (B)', 'Attempting to cause bodily harm or threatening another person with violence without physical contact or injury occurring.', 'PC200 (B)', 'infraction', 5500, 0, 0, 1, '2026-03-19 00:32:02'),
	(191, 1, 'Simple Assault (A)', 'Attempting to cause bodily harm or threatening another person with violence.', 'PC200 (A)', 'misdemeanor', 6000, 22, 0, 1, '2026-03-19 00:32:43'),
	(192, 1, 'Battery', 'Unlawfully striking or applying physical force to another individual.', 'PC201', 'misdemeanor', 6500, 24, 0, 1, '2026-03-19 00:33:22'),
	(193, 1, 'Domestic Battery', 'Using physical force against a spouse, partner, or household member during a dispute.', 'PC202', 'misdemeanor', 6750, 28, 0, 1, '2026-03-19 00:34:08'),
	(194, 1, 'Criminal Threats', 'Making credible threats of violence toward another individual.', 'PC203', 'misdemeanor', 5000, 25, 0, 1, '2026-03-19 00:34:57'),
	(195, 1, 'Reckless Endangerment (A)', 'Engaging in dangerous behavior that places others at risk of serious injury.', 'PC204 (A)', 'misdemeanor', 7000, 26, 0, 1, '2026-03-19 00:35:32'),
	(196, 1, 'Reckless Endangerment (B)', 'Engaging in dangerous behavior that places others at risk of serious injury without resulting in actual harm.', 'PC204 (B)', 'infraction', 6900, 0, 0, 1, '2026-03-19 00:36:58'),
	(197, 1, 'Aggravated Assault', 'Assault that results in serious bodily injury or involves severe violence.', 'PC206', 'felony', 10000, 30, 0, 1, '2026-03-19 00:38:54'),
	(198, 1, 'Assault with Deadly Weapon', 'Assault committed while using or threatening the use of a weapon capable of causing severe injury.', 'PC207', 'felony', 13000, 40, 0, 1, '2026-03-19 00:39:38'),
	(199, 1, 'Kidnapping', 'Unlawfully detaining or transporting another individual against their will.', 'PC208', 'felony', 15000, 45, 0, 1, '2026-03-19 00:40:22'),
	(200, 1, 'Hostage Taking', 'Holding an individual captive in order to force demands or gain leverage.', 'PC209', 'felony', 18000, 50, 0, 1, '2026-03-19 00:40:58'),
	(201, 1, 'Assault on Peace Officer', 'Assaulting a law enforcement officer performing official duties.', 'PC210', 'felony', 22000, 60, 0, 1, '2026-03-19 00:42:01'),
	(202, 1, 'Assault on EMS Personnel', 'Assaulting emergency medical personnel during emergency response.', 'PC211', 'felony', 24500, 70, 0, 1, '2026-03-19 00:43:01'),
	(203, 1, 'Second Degree Murder', 'Intentional killing without premeditation.', 'PC212', 'felony', 45000, 450, 0, 1, '2026-03-19 00:43:46'),
	(204, 1, 'First Degree Murder', 'Premeditated killing of another individual.', 'PC213', 'felony', 50000, 500, 0, 1, '2026-03-19 00:44:44'),
	(205, 2, 'Trespassing', 'Entering private property without permission.', 'PC300', 'infraction', 2500, 0, 0, 1, '2026-03-19 00:47:04'),
	(206, 2, 'Grand Theft', 'Theft of high-value property exceeding felony threshold.', 'PC301', 'misdemeanor', 10000, 35, 0, 1, '2026-03-19 00:48:55'),
	(207, 2, 'Vehicle Theft', 'Unlawfully taking or exercising control over a motor vehicle without the ownerÃ¢â¬â¢s consent, with the intent to permanently or significantly deprive the owner of their property. This includes stealing, attempting to steal, or knowingly possessing a stolen vehicle.', 'PC302', 'felony', 12000, 35, 0, 1, '2026-03-19 00:50:00'),
	(208, 2, 'Burglary', 'Entering or unlawfully remaining within a building or structure with the intent to commit theft or any other criminal offense. This includes situations involving forced entry, trespassing into restricted areas, or intent to commit additional crimes beyond simple theft.', 'PC303', 'felony', 13000, 45, 0, 1, '2026-03-19 00:51:32'),
	(209, 2, 'Robbery', 'Taking property through force or intimidation.', 'PC304', 'felony', 14000, 50, 0, 1, '2026-03-19 00:52:59'),
	(210, 2, 'Armed Robbery', 'Robbery involving use or display of a weapon.', 'PC305', 'felony', 16000, 55, 0, 1, '2026-03-19 00:53:27'),
	(211, 2, 'Bank Robbery', 'Knowingly taking or attempting to take money or assets from a financial institution through force, intimidation, or threat of violence. This includes entering a bank or similar establishment with the intent to commit robbery, whether or not the act is successfully completed, and applies regardless of whether a weapon is displayed or used.', 'PC306', 'felony', 20000, 90, 0, 0, '2026-03-19 00:54:40'),
	(212, 2, 'ATM Tampering / Theft', 'Unlawfully breaking into, damaging, or tampering with an automated teller machine (ATM) with the intent to steal money or access secured contents. This includes attempts to force entry, bypass security mechanisms, or remove currency, whether successful or not.', 'PC307', 'felony', 16000, 65, 0, 0, '2026-03-19 00:56:13'),
	(213, 2, 'Store Robbery', 'Knowingly taking or attempting to take money, goods, or property from a retail store or business through force, intimidation, or threat of violence. This includes entering a business with the intent to commit robbery, whether or not the act is successfully completed, and applies regardless of whether a weapon is displayed or used.', 'PC308', 'felony', 14000, 46, 0, 1, '2026-03-19 00:57:36'),
	(214, 2, 'Jewelry Store Robbery', 'Knowingly taking or attempting to take high-value items, including jewelry or luxury goods, from a retail establishment through force, intimidation, or threat of violence. This includes smash-and-grab incidents, coordinated thefts, or entering with intent to commit robbery, whether successful or not, and regardless of whether a weapon is used.', 'PC309', 'felony', 22000, 60, 0, 1, '2026-03-19 00:58:32'),
	(215, 2, 'Home Invasion Robbery', 'Forcibly entering or unlawfully entering an occupied residence with the intent to commit robbery or any other criminal offense. This includes the use of force, intimidation, or threats against occupants, and applies regardless of whether property is successfully taken.', 'PC310', 'felony', 20000, 58, 0, 1, '2026-03-19 00:59:54'),
	(216, 2, 'Armored Truck Robbery', 'Knowingly taking or attempting to take money or valuables from an armored security transport vehicle through force, intimidation, or threat of violence. This includes intercepting, ambushing, or disabling the vehicle or its personnel, and applies whether or not the robbery is successfully completed.', 'PC311', 'felony', 22000, 75, 0, 1, '2026-03-19 01:00:46'),
	(217, 5, 'Possession of Illegal Weapon', 'Knowingly possessing, carrying, or having control over any weapon that is prohibited by law, including but not limited to restricted firearms, explosive devices, or other banned weapon systems. This charge applies regardless of intent to use and includes any weapon deemed unlawful under current regulations.', 'PC500', 'misdemeanor', 6000, 26, 0, 1, '2026-03-19 01:02:43'),
	(218, 5, 'Unlicensed Firearm Possession', 'Possessing, carrying, or having immediate access to a firearm without holding a valid and recognized firearm license issued by the appropriate governing authority. This includes both on-person carry and vehicle possession.', 'PC501', 'misdemeanor', 6500, 30, 0, 1, '2026-03-19 01:03:18'),
	(219, 5, 'Brandishing a Weapon', 'Displaying, pointing, or otherwise presenting a weapon in a threatening or aggressive manner with the intent to intimidate, coerce, or cause fear in another individual, without lawful justification such as self-defense.', 'PC502', 'felony', 11000, 35, 0, 1, '2026-03-19 01:04:09'),
	(220, 5, 'Discharging Firearm in City Limits', 'Discharging a firearm within city limits or populated areas without lawful justification. This includes any intentional firing of a weapon that is not in self-defense or otherwise legally permitted.', 'PC503', 'felony', 13000, 38, 0, 1, '2026-03-19 01:05:07'),
	(221, 5, 'Reckless Discharge of Firearm', 'Firing a firearm in a negligent or reckless manner that creates a substantial risk of injury to others or damage to property, regardless of whether actual harm occurs.', 'PC504', 'felony', 13000, 40, 0, 1, '2026-03-19 01:06:06'),
	(222, 5, 'Possession of Automatic Weapon', 'Knowingly possessing or controlling a fully automatic firearm or any weapon modified to operate in a fully automatic capacity, where such weapons are prohibited by law.', 'PC505', 'felony', 15000, 60, 0, 1, '2026-03-19 01:07:00'),
	(223, 5, 'Possession of Explosive Device', 'Possessing, transporting, or controlling explosive materials or devices without proper authorization, licensing, or lawful purpose, including improvised explosive devices or military-grade explosives.', 'PC506', 'felony', 25000, 100, 0, 1, '2026-03-19 01:07:38'),
	(224, 5, 'Possession of Illegal Weapon Modifications', 'Possessing or utilizing prohibited weapon modifications or attachments, including but not limited to suppressors, extended magazines, or conversion devices, in violation of applicable laws.', 'PC507', 'felony', 9500, 25, 0, 1, '2026-03-19 01:08:28'),
	(225, 5, 'Manufacturing Illegal Weapons', 'Producing, assembling, or modifying firearms or prohibited weapons without proper licensing or authorization, including the creation of unregistered or unserialized firearms.', 'PC508', 'felony', 17000, 65, 0, 1, '2026-03-19 01:09:24'),
	(226, 5, 'Weapon Trafficking', 'Selling, distributing, transporting, or otherwise facilitating the illegal trade of firearms or weapons without proper licensing, documentation, or legal authorization.', 'PC509', 'felony', 18000, 100, 0, 1, '2026-03-19 01:10:14'),
	(227, 5, 'Straw Purchasing Firearms', 'Purchasing or attempting to purchase a firearm on behalf of another individual who is prohibited from legally owning or possessing firearms.', 'PC510', 'felony', 18500, 45, 0, 1, '2026-03-19 01:11:18'),
	(228, 5, 'Altering Firearm Serial Number', 'Removing, defacing, or altering the serial number or identifying markings on a firearm with the intent to conceal ownership, origin, or tracking.', 'PC511', 'felony', 17000, 40, 0, 1, '2026-03-19 01:12:14'),
	(229, 5, 'Possession of Firearm by Prohibited Person', 'Possessing, carrying, or having access to a firearm while being legally prohibited from doing so due to prior convictions, restraining orders, or other legal restrictions.', 'PC512', 'felony', 17500, 72, 0, 1, '2026-03-19 01:13:34'),
