	(231, 11, 'Hunting Without License', 'Knowingly engaging in the act of hunting wildlife without possessing a valid and active hunting license issued by the appropriate wildlife authority. This includes pursuing, tracking, wounding, or attempting to harvest any animal without proper legal authorization, regardless of success.', 'PC700', 'misdemeanor', 4500, 25, 0, 1, '2026-03-19 01:19:02'),
	(232, 11, 'Hunter Orange Violation', 'Failing to wear required hunter orange or high-visibility safety clothing while actively hunting in designated areas. This requirement is intended to ensure visibility and reduce the risk of accidental injury.', 'PC701', 'infraction', 1200, 0, 0, 1, '2026-03-19 01:20:03'),
	(233, 11, 'Hunting Protected Species', 'Hunting, harming, or attempting to hunt wildlife designated as protected, endangered, or restricted under conservation laws, regardless of outcome.', 'PC702', 'felony', 12000, 34, 0, 1, '2026-03-19 01:21:10'),
	(234, 11, 'Over Limit Hunting', 'Killing wildlife exceeding the legally permitted daily hunting limits. (30x Meat // 10x Pelts)', 'PC703', 'misdemeanor', 5000, 15, 0, 1, '2026-03-19 01:22:32'),
	(235, 11, 'Hunting Outside Designated Zone', 'Knowingly engaging in hunting activities outside of legally designated hunting zones or approved areas as defined by wildlife regulations. This includes pursuing, tracking, or attempting to harvest wildlife in restricted locations such as urban areas, protected land, or zones where hunting is not permitted.', 'PC704', 'misdemeanor', 5000, 20, 0, 1, '2026-03-19 01:24:40'),
