	(238, 4, 'Failure to Present Driver\'s License', 'Operating a motor vehicle or motorcycle without having a valid drivers license in their immediate possession at the time of lawful request by a peace officer. This applies even if the individual holds a valid license but is unable to physically present it when required.', 'PC635', 'infraction', 2500, 0, 1, 1, '2026-03-19 01:36:57'),
	(239, 5, 'Failure to Present Firearm / Hunting License', 'Carrying or possessing a firearm, or engaging in hunting activities, without having the required valid firearm license, permit, or hunting license in their immediate possession at the time of lawful request by a peace officer. This applies even if the individual is properly licensed but fails to physically present proof of authorization when required.', 'PC514', 'infraction', 4500, 0, 0, 1, '2026-03-19 01:39:50'),
