INSERT INTO `vx_mdt_incidents` (`id`, `markdown`, `tags`, `gallery`, `last_update`, `author`, `title`, `dep_id`, `dep_type`, `is_restricted`, `min_rank_priority`, `created_at`) VALUES
	(2, '{"type":"doc","content":[{"type":"heading","attrs":{"level":4},"content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"101 TODD WILLIAMS | 2026-03-22 @ 15:00 MDT | RECKLESS DRIVING @ CAPITAL BLVD / POPULAR ST"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"ADD-ON:"},{"type":"text","text":" The vehicle owner was asked to exit the building but failed, The vehicle was impounded for reckless driving, with a fine of $3,750 issued."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"101 Todd Williams was on patrol in the area of Capital Blvd and Popular St when he observed a 4-door blue van traveling eastbound on Capital Blvd approaching the intersection at Popular St. The vehicle attempted to make a left turn onto northbound Popular St but lost control while doing so, likely due to rainy conditions."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The vehicle failed to stop when prompted by 101 Todd Williams. The driver then parked the vehicle and exited on foot, ignoring lawful commands to stop. The individual proceeded to enter a nearby building."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Due to the suspectâs failure to comply and the potential risk posed. The location entered by the suspect was considered dangerous, as the individual could be waiting on the other side or attempting to evade further."}]}]}', '[{"color":"#06b6d4","title":"Traffic"},{"color":"#64748b","title":"Closed"}]', '[{"url":"https://r2.fivemanage.com/image/BBP2D9EV3kXE.webp","title":"VEHICLE","timestamp":1774212740},{"url":"https://r2.fivemanage.com/image/pp44RhK1iEes.webp","title":"1","timestamp":1774214510}]', '2026-03-24 23:42:29', 'Todd Williams', 'Reckless Driving - 1NT856LS', 2, 'law', 0, NULL, '2026-03-22 20:50:50'),
	(3, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"Unit 102, Officer Josh Sims, was en route to Pill Box to ensure an injured individual arrived safely. While stopped at a red light near Elgin Avenue, he observed a vehicle traveling through the intersection against the red light without headlights or taillights illuminated."}]},{"type":"paragraph","content":[{"type":"text","text":"A traffic stop was initiated. Upon contact, nothing unusual was observed, and the driver was compliant. no Citations were issued. The driver was advised to obey traffic signals and to repair the vehicleâs lighting as soon as possible due to safety concerns."}]}]}', '[{"color":"#64748b","title":"Closed"},{"color":"#06b6d4","title":"Traffic"}]', '[]', '2026-03-31 03:51:05', 'Josh Sims', 'Disregarding a TCD - Tony Walker', 2, 'law', 0, NULL, '2026-03-29 21:07:06'),
	(4, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":"102 Josh Sims was monitoring traffic along Integrity Way when he observed a vehicle running a red light. The vehicle was subsequently stopped at Pillbox. Upon making contact with the driver, identified as Mrs. Coco Martin, Officer Sims was informed that the driver was bleeding, which was the reason for her failure to stop at the red light."}]},{"type":"paragraph","content":[{"type":"text","text":"After assessing the situation, Officer Sims determined that there was no immediate threat to public safety and opted to issue a written warning rather than a citation. No further action was taken."}]}]}', '[{"color":"#64748b","title":"Closed"},{"color":"#06b6d4","title":"Traffic"}]', '[]', '2026-03-31 03:54:55', 'Josh Sims', 'Disregarding a TCD - Coco Martin', 2, 'law', 0, NULL, '2026-03-30 00:18:29'),
	(5, '{"type":"doc","content":[{"type":"heading","attrs":{"level":4},"content":[{"type":"text","marks":[{"type":"textStyle","attrs":{"color":"#7591a8","backgroundColor":null}},{"type":"bold"}],"text":"101 TODD WILLIAMS | 2026-04-01 @ 19:28 MDT | FINGERPRINT IDENTIFICATION"}]},{"type":"paragraph","content":[{"type":"text","text":"This supplemental report is submitted in reference to the stolen vehicle and carjacking investigation documented on 2026-03-30."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Fingerprint evidence previously recovered from the interior driverâs side of the stolen vehicle (Fingerprint ID: OHT78N9W5R161JK) has been formally processed through the system. The fingerprint has returned a positive identification to Carson Wheels."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"This confirmed match provides direct physical evidence placing Carson Wheels inside the stolen vehicle. When combined with prior observations, including a matching clothing description and proximity to the scene, this significantly advances the investigation."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Based on the totality of the evidence, probable cause has been established to identify Carson Wheels as a primary suspect in this case. This supplemental update has been officially documented and appended to the original report for continued investigative and enforcement action."}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"textStyle","attrs":{"color":"#7591a8","backgroundColor":null}},{"type":"bold"}],"text":"101 TODD WILLIAMS | 2026-03-30 @ 17:26 MDT | STOLEN VEHICLE RECOVERED / FINGERPRINT EVIDENCE"}]},{"type":"paragraph","content":[{"type":"text","text":"101 TODD WILLIAMS was at MRPD on a break when a call for service was received regarding an active carjacking. 101 TODD WILLIAMS responded immediately to the area."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Upon arrival, a gray 4-door van was located running and positioned partially on the sidewalk. A male subject was observed in the area wearing blue dress pants and a blue dress shirt. The individual appeared to be an older male with a beard and was seen walking away from the scene on Northwest Mirror Park Boulevard."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The vehicle was located on Tangerine St, positioned southbound between Mirror Park Boulevard and Bridge Street. A search of the vehicle was conducted, during which a fingerprint (NO RETURN) was located on the driverâs side interior. The male subject observed in the area was not wearing gloves and stated that a female had run him over."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The vehicle was confirmed to be linked to a prior vehicle theft that occurred on Eclipse Blvd, West Vinewood, near the pawn shop. The pawn shop owner, "},{"type":"text","marks":[{"type":"bold"}],"text":"Carson Wheels"},{"type":"text","text":", matches the clothing description observed on scene and is known to commonly wear the same attire."}]},{"type":"paragraph","content":[{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"EVIDENCE:"}]},{"type":"bulletList","content":[{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Type:"},{"type":"text","text":" Fingerprint"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 2026-03-30 @ 19:28 MDT"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Location:"},{"type":"text","text":" Tangerine St"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Plate:"},{"type":"text","text":" 21CDP704"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Fingerprint ID:"},{"type":"text","text":" OHT78N9W5R161JK"}]}]}]},{"type":"paragraph","content":[{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"VEHICLE:"}]},{"type":"bulletList","content":[{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Model:"},{"type":"text","text":" Rumpo"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Color:"},{"type":"text","text":" Gray"}]}]},{"type":"listItem","attrs":{"color":""},"content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Plate:"},{"type":"text","text":" 21CDP704"}]}]}]},{"type":"paragraph"}]}', '[{"color":"#22c55e","title":"Open"},{"color":"#eab308","title":"Under Investigation"}]', '[{"url":"https://r2.fivemanage.com/image/p2ags1B48km1.webp","timestamp":1774914971,"title":"STOLEN VEHICLE"},{"url":"https://r2.fivemanage.com/image/i0WNnVZRE8rt.png","timestamp":1774914998,"title":"LOCATION VRHICLE WAS FOUND"},{"url":"https://r2.fivemanage.com/image/PHA0i6WUPke2.png","timestamp":1774915009,"title":"CALL"},{"url":"https://r2.fivemanage.com/image/TIz4JmgDMEgC.png","timestamp":1774915403,"title":"Carson Wheels (Y ACCOUNT)"}]', '2026-04-02 01:37:13', 'Todd Williams', 'Vehicle Theft/Tampered - 21CDP704', 2, 'law', 0, NULL, '2026-03-30 23:36:53'),
	(6, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","text":" 102 Josh Sims, was traveling southbound on Las Lugnus Blvd en route to a call regarding a speeding vehicle detected by a speed camera. While responding, Officer Sims observed a tow truck traveling on Las Lugnus Blvd and turning toward the Mech Tunnel."}]},{"type":"paragraph","content":[{"type":"text","text":"The vehicle was visually estimated and later confirmed to be traveling approximately 75 MPH in a posted 55 MPH zone. The driver was also observed disregarding a traffic control device."}]},{"type":"paragraph","content":[{"type":"text","text":"A traffic stop was conducted just prior to LSC. The driver was identified as Ms. Allie Glasser. Upon contact, Ms. Glasser stated that she did not have a driverâs license or identification on her person. She remained compliant throughout the stop and explained that she had just gotten off a plane."}]},{"type":"paragraph","content":[{"type":"text","text":"Due to the circumstances and the driverâs cooperation, no citations were issued. A written warning was given."}]}]}', '[{"color":"#64748b","title":"Closed"},{"color":"#06b6d4","title":"Traffic"}]', '[]', '2026-03-31 03:56:29', 'Josh Sims', 'Disregarding a TCD - Allie Glasser', 2, 'law', 0, NULL, '2026-03-31 02:38:49'),
	(8, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"2026-04-07 @ 6:39PM MDT || 101 TODD WILLIAMS | Suspicious Exchange Involving Unknown Male Subject"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"UPDATED:"},{"type":"text","text":" 102 JOSH SIMS has reported spotting the same individual previously identified as a "},{"type":"text","marks":[{"type":"bold"}],"text":"Person of Interest"},{"type":"text","text":" in the area of another suspicious exchange. The individualâs continued presence and involvement in similar activity strengthens the pattern of behavior observed in prior incidents."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Assessment:"}]},{"type":"paragraph","content":[{"type":"text","text":"This sighting further supports reasonable suspicion that the individual may be actively involved in ongoing criminal activity within the area."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Action Recommended:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Continue surveillance of the individual"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Attempt identification and field interview if lawful grounds are established"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Cross-reference with prior reports and evidence"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Trooper Statement:"}]},{"type":"paragraph","content":[{"type":"text","text":"{102 Josh Sims}"}]},{"type":"paragraph"},{"type":"paragraph"},{"type":"paragraph"},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"2026-04-07 @ 3:30PM MDT || 101 TODD WILLIAMS | Suspicious Exchange Involving Unknown Male Subject"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"INVOLVED SUBJECT:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Unknown White Male"},{"type":"hardBreak"},{"type":"text","text":"â¢ Wearing black and green leather jacket"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"VEHICLE DESCRIPTION:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Black 2-door vehicle"},{"type":"hardBreak"},{"type":"text","text":"â¢ Additional identifiers: Unknown"}]},{"type":"paragraph","content":[{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"INCIDENT SUMMARY:"},{"type":"hardBreak"},{"type":"text","text":"While on patrol, the reporting Trooper observed an unknown white male wearing a black and green leather jacket near a black 2-door vehicle. The subject was seen engaging in a brief hand-to-hand exchange with another individual. This was not the first occurrence involving the subject. The individual has been previously linked to approximately 4â6 similar hand-to-hand exchanges in the same area, indicating a pattern of behavior consistent with ongoing street-level transactions."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"PROBABLE CAUSE STATEMENT:"},{"type":"hardBreak"},{"type":"text","text":"Based on the Trooper\'s training and experience, the repeated involvement in multiple hand-to-hand exchanges, combined with the observed interaction, establishes reasonable suspicion of ongoing narcotics distribution or related illegal activity."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"GROUNDS FOR STOP / SEARCH:"}]},{"type":"paragraph","content":[{"type":"text","text":"The decision to conduct an investigative stop and potential search is based on the totality of circumstances observed by the reporting Trooper. The subject was seen engaging in a hand-to-hand exchange consistent with street-level narcotics transactions. Additionally, the subject has been previously linked to approximately 4â6 similar incidents in the Same area / Seen in the city around the same call, establishing a clear pattern of behavior. The repeated presence of the subject in a high-frequency exchange location further supports suspicion of ongoing criminal activity."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"Based on the Trooperâs training and experience, these factors collectively establish reasonable suspicion to detain the individual for further investigation. Should additional indicators be observed during the stop (including but not limited to visible contraband, admissions), probable cause may be established to conduct a lawful search of the subject and/or vehicle."}]}]}', '[{"title":"Open","color":"#22c55e"},{"title":"Under Investigation","color":"#eab308"}]', '[]', '2026-04-08 00:56:33', 'Todd Williams', 'Suspicious Exchange - Unknown Male', 2, 'law', 0, NULL, '2026-04-07 21:26:13'),
	(9, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"ORIGINAL CALL DETAILS:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Call Type: Carjacking"},{"type":"hardBreak"},{"type":"text","text":"â¢ Time of Call: 15:32 MDT"},{"type":"hardBreak"},{"type":"text","text":"â¢ Area: Del Perro Fwy, Pacific Bluffs"},{"type":"hardBreak"},{"type":"text","text":"â¢ Vehicle Description: Metallic black (noted as worn white in system)"},{"type":"hardBreak"},{"type":"text","text":"â¢ Plate: 09BXO506"},{"type":"hardBreak"},{"type":"text","text":"â¢ Direction of Travel: Southbound"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"EVIDENCE RECOVERED:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Evidence Type: Fingerprint"},{"type":"hardBreak"},{"type":"text","text":"â¢ Location Found: On the handlebars"},{"type":"hardBreak"},{"type":"text","text":"â¢ Fingerprint ID: MV0UZP1SLX0WK2G"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"INVOLVED / PERSON OF INTEREST:"},{"type":"hardBreak"},{"type":"text","text":"â¢ "},{"type":"text","marks":[{"type":"bold"}],"text":"Albert Richards"},{"type":"text","text":" â Person of Interest (FINGERPRINT MATCH - MV0UZP1SLX0WK2G)"}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"INCIDENT SUMMARY:"},{"type":"hardBreak"},{"type":"text","text":"At approximately 17:35 MDT, officers responded to a call regarding a possible vehicle theft and/or tampering on Del Perro Fwy in the Pacific Bluffs area. Upon arrival, officers located a metallic black "},{"type":"text","marks":[{"type":"bold"}],"text":"Blazer Lifeguard"},{"type":"text","text":" bearing plate 09BXO506. The vehicle showed signs consistent with theft and/or tampering. During the investigation, a suspect matching prior descriptions was observed fleeing the area on foot, running along the beach. A forensic examination of the vehicle was conducted on scene, resulting in the recovery of a viable fingerprint."}]},{"type":"paragraph","content":[{"type":"text","text":"The fingerprint was collected and logged for further investigative follow-up."}]}]}', '[{"title":"Closed","color":"#64748b"}]', '[]', '2026-04-08 02:15:03', 'Todd Williams', 'Attempted Vheicle Theft/Tampering - (POI) Albert Richards', 2, 'law', 0, NULL, '2026-04-07 21:43:58'),
	(10, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INVESTIGATIVE INCIDENT REPORT"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"CALL DETAILS:"},{"type":"hardBreak"},{"type":"text","text":"Title: Suspicious excange/ Evading"},{"type":"hardBreak"},{"type":"text","text":"Date: 2026-04-08"},{"type":"hardBreak"},{"type":"text","text":"Time: 9:30 pm"},{"type":"hardBreak"},{"type":"text","text":"Reporting Officer: "},{"type":"text","marks":[{"type":"textStyle","attrs":{"color":"rgb(125, 120, 120)","backgroundColor":"rgba(125, 120, 120, 0.082)"}}],"text":"@108 Chad Cooper"},{"type":"hardBreak"},{"type":"text","text":"Location: [Full Location]"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"Call Type: "},{"type":"hardBreak"},{"type":"text","text":"Time of Call: "},{"type":"hardBreak"},{"type":"text","text":"Dispatch Notes: "},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INVOLVED / PERSON(S) OF INTEREST:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Name: "},{"type":"text","marks":[{"type":"bold"}],"text":"Albert Richards"},{"type":"hardBreak"},{"type":"text","text":"â¢ DOB: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Description: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Role: Suspect [POI]"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"VEHICLE INFORMATION:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Plate: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Model: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Color: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Additional Description: "},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"EVIDENCE RECOVERED:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Type: Fingerprint"},{"type":"hardBreak"},{"type":"text","text":"â¢ Description: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Location Found: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Evidence #: MV0UZP1SLX0WK2G"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INCIDENT SUMMARY:"},{"type":"hardBreak"},{"type":"text","text":"108 responded to a suspicious person call at a construction site and observed a male going up to multiple workers at the scene but did not see any interaction besides the individual going to the workers and both suspect and individual walking away. 108 was able to stop the suspect and chat with him to see what was going on and the suspect claimed that he was looking for a job and that the workers kept telling him that he could not work there. 101 arrived on scene as 108 was having a conversation with the suspect. 108 told the suspect to stay on the sidewalk while he went and talked to 101. Suspect then got into the vehcile that was there which was a gray in color banshee with a chrome stripe down the middle. Suspect then began to take off and 101 as well as 108 took chase. Suspect did stop down the road and when confronted as to why he took off, he responded with that he was told to wait for a few minutes and said it was a few minutes and so he left. 108 asked for an ID while stopped the second time and said that he did not have his license or ID on him. Asked if we could run his name in the system in which we obliged and gave us the name of Baja Boom. 108 asked 101 to run the name to see if there was a active license under that name and as 108 asked the suspect to step out of the her, the suspect took off on a 10-80 in which both 101 and 108 were involved with. The 10-80 went on for approx. 5-6 minutes before loosing visual of suspect. Then got a grand theft call and as 101 and 108 got on scene of the call, the banshee in question was in the middle of the roadway. Got prints off of vehicle that comes back to a Albert"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"ACTIONS TAKEN:"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"ADDITIONAL NOTES:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Surveillance / CCTV: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Witness Statements: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Trooper Observations: "},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"PROBABLE CAUSE STATEMENT:"},{"type":"hardBreak"},{"type":"text","text":"[Explain clearly WHY you believe a crime occurred based on facts, training, and evidence.]"},{"type":"hardBreak"}]}]}', '[{"title":"Closed","color":"#64748b"}]', '[]', '2026-04-08 03:46:26', 'Todd Williams', 'Suspicious Exchange / Evading - Albert Richards', 2, 'law', 0, NULL, '2026-04-08 02:07:34'),
