TION:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Name: ALBERT RICHARDS"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ DOB: 1994/05/16"},{"type":"hardBreak"},{"type":"text","text":"â¢ State ID#: 83748"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ License #: N/A"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"---"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"VEHICLE INFORMATION:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Plate: 42ULW904"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Model: UNKNOWN"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Color: Mal-Black"}]},{"type":"paragraph","content":[{"type":"text","text":"---"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INCIDENT DETAILS:"}]},{"type":"paragraph","content":[{"type":"text","text":"[Summary of violation (speeding, reckless driving, etc.)]"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"---"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"EVIDENCE / OBSERVATION:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Radar Speed: 80 - 120"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Visual Estimate: UNKNOWN"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Additional Notes: N/A"},{"type":"hardBreak"},{"type":"text","text":"â¢ Trooper Observations:"}]}]}', '[{"title":"Closed","color":"#64748b"},{"title":"Violent Crime","color":"#dc2626"}]', '[{"title":"1","timestamp":1775701477,"url":"https://r2.fivemanage.com/image/XilMtyUqoAgt.webp"},{"title":"Photo taken of a Masked Person doing handoffs","timestamp":1775701607,"url":"https://r2.fivemanage.com/image/8wg7n87G3a18.webp"}]', '2026-04-