	(12, '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Traffic Stop Report"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Officer:"},{"type":"text","text":" "},{"type":"text","marks":[{"type":"textStyle","attrs":{"color":"rgb(125, 120, 120)","backgroundColor":"rgba(125, 120, 120, 0.082)"}}],"text":"@102 Josh Sims"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 2026-04-09"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Location: lower power street"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Vehicle Information"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Plate: 26sse458"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Make/Model: Ruiner"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Narrative"}]},{"type":"paragraph","content":[{"type":"text","text":"102 Josh sims was in the area responding to a reckless driving call and actively searching for the reported speeding vehicle. While approaching Upper Pill Box, Unit 102 observed a vehicle that appeared to be traveling at a high rate of speed. Although no speed was confirmed by radar, a visual estimate placed the vehicleâs speed at approximately 65â70 MPH."}]},{"type":"paragraph","content":[{"type":"text","text":"Unit 102 then observed the vehicle make a right turn while disregarding a traffic control device (TCD). As Unit 102 attempted to catch up, the vehicle was observed disregarding two additional traffic control devices before eventually coming to a complete stop at Lower Power Street."}]},{"type":"paragraph","content":[{"type":"text","text":"One citation was issued for failure to obey a traffic control device."}]}]}', '[{"color":"#64748b","title":"Closed"},{"color":"#06b6d4","title":"Traffic"}]', '[]', '2026-04-09 03:52:50', 'Josh Sims', 'Disregarding TCD - Tony Reed', 2, 'law', 0, NULL, '2026-04-09 03:35:51'),
	(13, '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Traffic Stop Report"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Officer:"},{"type":"text","text":" 102 josh Sims"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 2026-04-13"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Location: south rockford drive"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Vehicle Information"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Plate: 48tsi415"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Make/Model: sentnal"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Narrative"}]},{"type":"paragraph","content":[{"type":"text","text":"102 Josh sims was sitting across the street from LTD on little soal when he observed a vehicle that seemed to be going a little fast so he pulled out to try and clock the vehicle at a speed he then seen the vehicle go thru 2 TCD befor making a final stop at south rockford drive "}]}]}', '[{"color":"#06b6d4","title":"Traffic"},{"color":"#64748b","title":"Closed"}]', '[]', '2026-04-13 01:46:48', 'Josh Sims', 'Disregarding TCD - Sal Valentino', 2, 'law', 0, NULL, '2026-04-13 01:43:00'),
	(14, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INVESTIGATIVE INCIDENT REPORT"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"INCIDENT UPDATE â ARREST & PURSUIT SUMMARY - Case #:"},{"type":"text","text":" 2026-0014"}]},{"type":"paragraph","content":[{"type":"text","text":"During active patrol, 101 Todd Williams conducted a traffic stop on "},{"type":"text","marks":[{"type":"bold"}],"text":"Davis Ave near Maze Bank Arena"},{"type":"text","text":" on a vehicle confirmed stolen. The driver was identified as "},{"type":"text","marks":[{"type":"bold"}],"text":"Lia Valentino"},{"type":"text","text":". Upon contact, the driver was unable to provide keys or proof of lawful possession of the vehicle. When given lawful commands to exit the vehicle, the suspect refused and fled, initiating a pursuit. At the time, 101 Todd Williams was the sole unit on duty."}]},{"type":"paragraph","content":[{"type":"text","text":"The suspect engaged in "},{"type":"text","marks":[{"type":"bold"}],"text":"reckless and dangerous evasion"},{"type":"text","text":", traveling at high speeds throughout the city, entering oncoming lanes of traffic, colliding with multiple vehicles, and attempting to strike pedestrians. A "},{"type":"text","marks":[{"type":"bold"}],"text":"Tactical Vehicle Intervention (TVI)"},{"type":"text","text":" was executed near the pier, successfully disabling the vehicle. The suspect exited armed with a "},{"type":"text","marks":[{"type":"bold"}],"text":"hatchet"},{"type":"text","text":", attempted to carjack another vehicle (unsuccessful), then escalated by producing a "},{"type":"text","marks":[{"type":"bold"}],"text":"baseball bat"},{"type":"text","text":", successfully carjacking a "},{"type":"text","marks":[{"type":"bold"}],"text":"black 4-door vehicle"},{"type":"text","text":", and continued to flee. "},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"A second pursuit ensued. A "},{"type":"text","marks":[{"type":"bold"}],"text":"secondary TVI"},{"type":"text","text":" was conducted on "},{"type":"text","marks":[{"type":"bold"}],"text":"Vespucci Blvd near Alta Street Apartments"},{"type":"text","text":", resulting in the suspect vehicle losing control and rolling onto its roof. The maneuver was conducted at approximately "},{"type":"text","marks":[{"type":"bold"}],"text":"60â80 MPH"},{"type":"text","text":" in a controlled area with minimal civilian presence."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The suspect fled on foot while armed with a "},{"type":"text","marks":[{"type":"bold"}],"text":"baseball bat"},{"type":"text","text":" and repeatedly failed to comply with lawful commands. Due to the immediate threat posed, the suspect was "},{"type":"text","marks":[{"type":"bold"}],"text":"tased twice"},{"type":"text","text":", successfully brought into custody, and placed in restraints without further incident."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The suspect was observed to be actively bleeding and was transported to "},{"type":"text","marks":[{"type":"bold"}],"text":"Pillbox Medical Center (Lower)"},{"type":"text","text":" for treatment. After being medically cleared by EMS, the suspect was transported to "},{"type":"text","marks":[{"type":"bold"}],"text":"MRPD"},{"type":"text","text":" for processing."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"EVIDENTIARY LINK:"}]},{"type":"paragraph","content":[{"type":"text","text":"The suspect is "},{"type":"text","marks":[{"type":"bold"}],"text":"positively linked"},{"type":"text","text":" to prior incidents through matching fingerprint evidence:"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Fingerprint ID:"},{"type":"text","text":" V4RRN99O14KRYYD"},{"type":"hardBreak"},{"type":"text","text":"This fingerprint matches evidence recovered from multiple stolen vehicle scenes, including the Lifeinvader incident and Palomino Ave recovery, establishing a clear pattern of involvement."}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","marks":[{"type":"bold"}],"text":"DISPOSITION:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ "},{"type":"text","marks":[{"type":"bold"}],"text":"Suspect:"},{"type":"text","text":" Lia Valentino"},{"type":"hardBreak"},{"type":"text","text":"â¢ "},{"type":"text","marks":[{"type":"bold"}],"text":"Status:"},{"type":"text","text":" In Custody"},{"type":"hardBreak"},{"type":"text","text":"â¢ "},{"type":"text","marks":[{"type":"bold"}],"text":"Fine Issued:"},{"type":"text","text":" $9,750 (75% reduction applied)"},{"type":"hardBreak"},{"type":"text","text":"â¢ "},{"type":"text","marks":[{"type":"bold"}],"text":"Sentence:"},{"type":"text","text":" 48 months (45% reduction applied)"},{"type":"hardBreak"}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"INCIDENT SUMMARY (UPDATE):"}]},{"type":"paragraph","content":[{"type":"text","text":"While actively handling a separate call for service, 101 Todd Williams received an additional report of a stolen vehicle in the area. While canvassing the surrounding area, a vehicle was located overturned (upside down) and still running. The scene was secured, and a search of the vehicle was conducted. During the search, a fingerprint was recovered from the vehicle."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"The recovered fingerprint returned a "},{"type":"text","marks":[{"type":"bold"}],"text":"match"},{"type":"text","text":" to previously collected evidence:"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Type:"},{"type":"text","text":" Fingerprint"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 04/24/26 @ 09:26"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Location:"},{"type":"text","text":" Palomino Ave"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Plate:"},{"type":"text","text":" 47JNA682"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Fingerprint ID:"},{"type":"text","text":" V4RRN99O14KRYYD"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"This fingerprint matches the same fingerprint recovered in the prior Lifeinvader carjacking investigation, linking the two incidents to the same unidentified individual."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"This establishes a pattern and strengthens the connection between both stolen vehicle incidents. The individual associated with the fingerprint is now considered a primary suspect in the ongoing investigations."}]},{"type":"horizontalRule"},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"CALL DETAILS:"},{"type":"hardBreak"},{"type":"text","text":"Title: STOLEN VEHICLE RECOVERED"},{"type":"hardBreak"},{"type":"text","text":"Date: 2026-04-24"},{"type":"hardBreak"},{"type":"text","text":"Time: 7PM MDT"},{"type":"hardBreak"},{"type":"text","text":"Reporting Officer: "},{"type":"text","marks":[{"type":"textStyle","attrs":{"color":"rgb(125, 120, 120)","backgroundColor":"rgba(125, 120, 120, 0.082)"}}],"text":"@101 Todd Williams"},{"type":"hardBreak"},{"type":"text","text":"Location: South Boulevard Del Perro @ Lifeinvader"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"Call Type: Car Jacking"},{"type":"hardBreak"},{"type":"text","text":"Time of Call: Around 7pm mdt"},{"type":"hardBreak"},{"type":"text","text":"Dispatch Notes: N/A"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INVOLVED / PERSON(S) OF INTEREST:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Name: LIA VALENTINO"},{"type":"hardBreak"},{"type":"text","text":"â¢ DOB: "},{"type":"hardBreak"},{"type":"text","text":"â¢ Description: FEMALE | 6 FOOT TALL | RED EYES"},{"type":"hardBreak"},{"type":"text","text":"â¢ Role: Suspect / POI"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"VEHICLE INFORMATION:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Plate: 82LIV805"},{"type":"hardBreak"},{"type":"text","text":"â¢ Model: N/A"},{"type":"hardBreak"},{"type":"text","text":"â¢ Color: GREEN"},{"type":"hardBreak"},{"type":"text","text":"â¢ Additional Description: N/A"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"EVIDENCE RECOVERED:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Type: Fingerprint"},{"type":"hardBreak"},{"type":"text","text":"â¢ Description: FOUND IN VEHICLE"},{"type":"hardBreak"},{"type":"text","text":"â¢ Location Found: South Boulevard Del Perro @ Lifeinvader"},{"type":"hardBreak"},{"type":"text","text":"â¢ Evidence ID: V4RRN99O14KRYYD"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"INCIDENT SUMMARY:"},{"type":"hardBreak"},{"type":"text","text":"101 Todd Williams responded to a reported carjacking in the area of Lifeinvader. Upon arrival, a vehicle was located parked along the side of the building with the engine still running and no occupants present. A search of the vehicle was conducted, during which a fingerprint was recovered from the interior. No suspects were located in the immediate area."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Prior to the incident, a firearms license had been issued to an individual who was instructed to attend the Lifeinvader location; however, they were not observed on scene upon arrival. Due to the timing and location, the individual has been noted as a person of interest pending further investigation. The investigation remains active while efforts are made to identify the individual linked to the recovered fingerprint and determine involvement in the reported carjacking."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"ACTIONS TAKEN:"}]},{"type":"paragraph","content":[{"type":"text","text":"â¢ Responded to active carjacking call"},{"type":"hardBreak"},{"type":"text","text":"â¢ Secured and cleared the vehicle"},{"type":"hardBreak"},{"type":"text","text":"â¢ Conducted search of vehicle"},{"type":"hardBreak"},{"type":"text","text":"â¢ Recovered and logged fingerprint evidence"},{"type":"hardBreak"},{"type":"text","text":"â¢ Canvassed surrounding area for suspects/witnesses"},{"type":"hardBreak"},{"type":"text","text":"â¢ Attempted to locate involved individual (negative contact)"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"ADDITIONAL NOTES:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Surveillance / CCTV: N/A"},{"type":"hardBreak"},{"type":"text","text":"â¢ Witness Statements: N/A"},{"type":"hardBreak"},{"type":"text","text":"â¢ Trooper Observations: Upon arrival, I observed a vehicle parked along the side of the Lifeinvader building with the engine still running and no occupants present. The condition and positioning of the vehicle were consistent with it being recently abandoned following a possible theft."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"---"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"PROBABLE CAUSE STATEMENT:"},{"type":"hardBreak"},{"type":"text","text":"Based on the totality of the circumstances, there is reasonable suspicion to believe that a carjacking or vehicle theft occurred in the area of Lifeinvader. The vehicle was located running and unattended, which is consistent with a recently stolen or abandoned vehicle. A fingerprint recovered from inside the vehicle indicates that an identifiable individual was present within the vehicle without confirmed lawful ownership or permission. Additionally, a subject who had recent contact with law enforcement was instructed to attend the same location shortly before the incident and was not observed on scene, placing them in close proximity to the time and location of the offense."}]},{"type":"paragraph"},{"type":"paragraph","content":[{"type":"text","text":"These factors establish probable cause to continue the investigation, identify the individual linked to the recovered fingerprint, and determine their involvement in the reported incident."},{"type":"hardBreak"}]}]}', '[{"color":"#64748b","title":"Closed"},{"color":"#06b6d4","title":"Traffic"},{"color":"#dc2626","title":"Violent Crime"}]', '[{"title":"VEHICLE","url":"https://r2.fivemanage.com/image/vSy1Q1Cn8wJ5.webp","timestamp":1777078193},{"title":"PLATE","url":"https://r2.fivemanage.com/image/OOCGfSk8rJTd.webp","timestamp":1777078231},{"title":"MUGSHOT1","url":"https://r2.fivemanage.com/image/JRIOpoKyTGXK.webp","timestamp":1777084485},{"title":"MUGSHOT2","url":"https://r2.fivemanage.com/image/vc9eE8niRzLT.webp","timestamp":1777084499}]', '2026-04-25 20:42:18', 'Todd Williams', 'Stolen Vehicle - Lia Valentino', 2, 'law', 0, NULL, '2026-04-25 00:47:45');
