INSERT INTO `vx_mdt_reports` (`id`, `markdown`, `tags`, `gallery`, `last_update`, `author`, `title`, `dep_id`, `dep_type`, `is_restricted`, `min_rank_priority`, `created_at`) VALUES
	(3, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"SASP PERFORMANCE REVIEW â 108 CHAD COOPER"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 2026-04-09 @ 6:10PM MDT"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Overview:"},{"type":"hardBreak"},{"type":"text","text":"108 Chad Cooper has demonstrated intermittent activity while serving with the San Andreas State Police. He has been on duty periodically and has shown some initiative within the department."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Tenure & Activity:"},{"type":"hardBreak"},{"type":"text","text":"â¢ Time in Service: 50 Days"},{"type":"hardBreak"},{"type":"text","text":"â¢ Total Duty Time: 15 Hours, 27 Minutes, 6 Seconds"},{"type":"hardBreak"},{"type":"text","text":"â¢ Activity (Last 14 Days): 3 Hours, 21 Minutes"},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Operational Performance:"},{"type":"hardBreak"},{"type":"text","text":"Chad Cooper has successfully participated in one arrest involving a suspect, utilizing coordinated backup support including Air One and HEAT units. This shows the ability to work within a team and follow direction during active situations."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"However, it has been noted that Chad requires additional guidance when handling calls, which is expected given this was his first active call. "},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","text":"Continued exposure and field experience will be necessary to build confidence and independence."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Promotion Consideration:"},{"type":"hardBreak"},{"type":"text","text":"Chad Cooper has applied for the position of "},{"type":"text","marks":[{"type":"bold"}],"text":"103 Major"},{"type":"text","text":". While he has shown some capability in the field, his current activity levels do not meet the departmentâs required minimum of "},{"type":"text","marks":[{"type":"bold"}],"text":"10 hours bi-weekly"},{"type":"text","text":"."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Final Determination:"},{"type":"hardBreak"},{"type":"text","text":"At this time, Chad Cooper "},{"type":"text","marks":[{"type":"bold"}],"text":"does not meet the activity requirements"},{"type":"text","text":" for promotion. If the required standard of 10 hours bi-weekly is not met, he will "},{"type":"text","marks":[{"type":"bold"}],"text":"not be eligible"},{"type":"text","text":" for advancement to the rank of 103 Major."},{"type":"hardBreak"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Recommendation:"},{"type":"hardBreak"},{"type":"text","text":"Chad Cooper should focus on increasing duty hours, gaining more call experience, and improving independence on scenes. With consistent activity and development, he may be reconsidered for promotion in the future."}]}]}', '[{"title":"Follow-up Required","color":"#f97316"}]', '[]', '2026-04-10 00:44:20', 'Todd Williams', 'INTERNAL PERFORMANCE REVIEW - 108 CHAD COOPER', 2, 'law', 1, 8, '2026-04-08 02:41:56'),
	(4, NULL, '[]', '[]', '2026-04-27 03:57:45', 'Artemis Moon', 'TEST', 3, 'ems', 0, NULL, '2026-04-27 03:57:45'),
	(6, '{"type":"doc","content":[{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Pillbox Hill Medical â Sandy Shores Airfield (SSAF) ="},{"type":"text","text":" Trainee demonstrated solid overall flight capability, including controlled takeoff and good altitude awareness. Primary area requiring improvement is "},{"type":"text","marks":[{"type":"bold"}],"text":"hover control"},{"type":"text","text":", specifically maintaining a steady position without drift during stationary flight & Landing."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Sandy Shores Airfield (SSAF) â Grapeseed Airfield (GSAF) ="},{"type":"text","text":" During the flight from Sandy Shores Airfield to Grapeseed Airfield, the trainee conducted a smooth and controlled takeoff with no issues observed. Throughout the flight, they maintained stable control of the aircraft, demonstrating good awareness of altitude and positioning. The landing at Grapeseed Airfield was completed in a controlled and accurate manner, showing confidence and proper handling of the aircraft."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Grapeseed Airfield (GSAF) â Paleto Bay PD (PBPD) ="},{"type":"text","text":" During the flight from Grapeseed Airfield to Paleto Bay PD, the trainee performed a strong and controlled takeoff and maintained good overall flight stability throughout the route. Upon arrival, the landing was completed safely; however, positioning near nearby trees required additional correction. The trainee showed fair control but will need to continue developing precision and obstacle awareness when operating in tighter landing zones. This is considered a normal area for improvement and is expected to improve with continued experience and training."}]},{"type":"paragraph","content":[{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Paleto Bay PD (PBPD) â Mission Row PD (MRPD) ="},{"type":"text","text":" During the flight from Paleto Bay PD to Mission Row PD, the trainee performed a good and controlled takeoff, followed by stable and consistent flight throughout the route. The approach and landing at Mission Row PD were completed without any safety concerns; however, the landing was only fair and showed signs of hesitation. The trainee would benefit from building confidence during final approach and touchdown, as well as continuing training to improve overall landing precision and consistency."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Mission Row PD (MRPD) â  (MCSW) ="},{"type":"text","text":" This flight segment was not conducted. No evaluation was completed for this route during the training session."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","marks":[{"type":"bold"},{"type":"underline"}],"text":"Mission Row PD (MRPD) â Pillbox Hill Medical ="},{"type":"text","text":" During the flight from Mission Row PD to Pillbox Hill Medical, the trainee demonstrated strong improvement compared to earlier segments. The takeoff was smooth and controlled, followed by a very stable and confident flight. The landing was completed successfully and showed overall good control of the aircraft; however, there is still room for improvement in consistency and precision. Continued training will help refine these skills further."},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"hardBreak"},{"type":"text","text":"The trainee has shown steady improvement throughout the training session and demonstrates a solid foundation in basic flight operations. They are encouraged to continue practicing, especially during downtime, to further develop confidence and precision in landings and hovering. At this time, the trainee is "},{"type":"text","marks":[{"type":"bold"}],"text":"not certified for Medevac operations"},{"type":"text","text":", as those require a higher level of training, consistency, and operational readiness."}]},{"type":"paragraph"},{"type":"paragraph"}]}', '[{"color":"#BFFFF6","title":"AIR-CERT | IN-PROGRESS"},{"color":"#64748b","title":"Confidential"},{"color":"#f97316","title":"Follow-up Required"}]', '[]', '2026-04-28 21:06:01', 'Todd Williams', 'ARTEMIS AIRMED CERT | BY: SASP COMMAD', 2, 'law', 1, 8, '2026-04-28 02:34:53'),
	(7, '{"type":"doc","content":[{"type":"heading","attrs":{"level":2},"content":[{"type":"text","text":"Patient Care Report"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Medic:"},{"type":"text","text":" "},{"type":"mention","attrs":{"id":"50592","label":"Moose Hallowman","mentionSuggestionChar":"@","color":"#ec4899"},"marks":[{"type":"textStyle","attrs":{"color":"#ec4899","backgroundColor":"rgba(236, 72, 153, 0.082)"}}]}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Date:"},{"type":"text","text":" 2026-04-30"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Patient Information"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Name:"},{"type":"text","text":" Barbara Brown"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Triage Level:"},{"type":"text","text":" Green - Minor"}]},{"type":"paragraph","content":[{"type":"text","marks":[{"type":"bold"}],"text":"Transported:"},{"type":"text","text":" No"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Chief Complaint"}]},{"type":"paragraph","content":[{"type":"text","text":"Fell off of her hover board and lost concious back and forth."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Assessment & Vitals"}]},{"type":"paragraph","content":[{"type":"text","text":"Upon arriving on scene patient was responsive, but did not recaal what had happened. A bystander was able to go and tell me that the patient had fell off of the hoverboard and hit her head pretty hard against the concrete floor near Pond Cafe. So the assesment for Barbra was a potential concussion, and scraped elbows."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Treatment Provided"}]},{"type":"paragraph","content":[{"type":"text","text":"Upon cleaning up and disenfecting the wound on both her head, and her elbows, she was bandaged up and then questioned and checked for any signs of a concussion. The test came back negative and she was then released upon her boyfriend coming to pick her up."}]},{"type":"heading","attrs":{"level":3},"content":[{"type":"text","text":"Disposition"}]},{"type":"paragraph","content":[{"type":"text","text":"Treated & Released"}]}]}', '[]', '[]', '2026-04-30 05:41:40', 'Moose Hallowman', 'Local Test', 3, 'ems', 0, NULL, '2026-04-30 05:40:52');
