	('89909', 2, 11, 'Josh', 'Sims', NULL, NULL, 'active', '2026-06-01 01:28:58', '2026-06-01 01:28:58', '{"type":"doc","content":[{"type":"paragraph"}]}', '[{"title":"Field Training Officer","color":"#EBFF26"},{"title":"High Enforcement Aggressive Traffic (CLASS A)","color":"#29FF3D"},{"title":"High Enforcement Aggressive Traffic (CLASS S)","color":"#00870D"},{"title":"High Enforcement Aggressive Traffic (CLASS S+)","color":"#00876C"},{"title":"Air Support Unit","color":"#2E0036"}]', 'https://images-ext-1.discordapp.net/external/trpC4UXKqhGd93p1Ezo6M3tEE-QuSnHStyAIs8TBHfs/https/r2.fivemanage.com/image/UDXNkCQeEWXn.png?format=webp&quality=lossless&width=675&height=511');
INSERT INTO `vx_mdt_templates` (`id`, `dep_id`, `title`, `content`, `record_type`, `arguments`, `author`, `created_at`, `last_update`) VALUES
	(1, 1, 'Traffic Stop Report', '<h2>Traffic Stop Report</h2><p><strong>Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Location:</strong> {location}</p><hr><h3>Vehicle Information</h3><p><strong>Plate:</strong> {plate}</p><p><strong>Make/Model:</strong> {vehicle_model}</p><hr><h3>Narrative</h3><p>{narrative}</p>', 'report', '[{"label":"Reporting Officer","key":"officer_name","type":"staff"},{"label":"Date of Stop","key":"date","type":"date"},{"placeholder":"e.g. Route 68 & Senora Fwy","label":"Location","key":"location","type":"text"},{"placeholder":"e.g. ABC1234","label":"License Plate","key":"plate","type":"text"},{"placeholder":"e.g. White Sultan RS","label":"Vehicle Make/Model","key":"vehicle_model","type":"text"},{"placeholder":"Describe the stop...","label":"Narrative","key":"narrative","type":"textarea"}]', 'System', 1773794336, 1773794336),
	(2, 1, 'Use of Force Incident', '<h2>Use of Force Report</h2><p><strong>Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Force Level:</strong> {force_level}</p><p><strong>Body Camera:</strong> {body_camera}</p><hr><h3>Subject</h3><p><strong>Name:</strong> {suspect_name}</p><hr><h3>Incident Summary</h3><p>{summary}</p><h3>Injuries</h3><p>{injuries}</p>', 'incident', '[{"label":"Officer","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"options":["Level 1 - Verbal","Level 2 - Physical","Level 3 - Less-Lethal","Level 4 - Lethal"],"label":"Force Level","key":"force_level","type":"select"},{"label":"Body Camera Active","key":"body_camera","unchecked_value":"Inactive","checked_value":"Active","type":"checkbox"},{"placeholder":"e.g. John Doe","label":"Subject Name","key":"suspect_name","type":"text"},{"placeholder":"Describe what happened...","label":"Summary","key":"summary","type":"textarea"},{"placeholder":"Describe any injuries...","label":"Injuries Sustained","key":"injuries","type":"textarea"}]', 'System', 1773794336, 1773794336),
	(3, 1, 'Evidence Collection Form', '<h2>Evidence Collection Log</h2><p><strong>Collector:</strong> {collector_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Case #:</strong> {case_number}</p><hr><h3>Evidence Description</h3><p><strong>Type:</strong> {evidence_type}</p><p><strong>Location Found:</strong> {location}</p><p><strong>Condition:</strong> {condition}</p><hr><h3>Evidence Photo</h3><p>{evidence_photo}</p><h3>Chain of Custody Notes</h3><p>{notes}</p>', 'evidence', '[{"label":"Collector","key":"collector_name","type":"staff"},{"label":"Collection Date","key":"date","type":"date"},{"placeholder":"e.g. 2024-0451","label":"Case Number","key":"case_number","type":"text"},{"options":["Firearm","Narcotics","Documents","Digital Media","Biological","Vehicle","Other"],"label":"Evidence Type","key":"evidence_type","type":"select"},{"placeholder":"e.g. 123 Grove St","label":"Location Found","key":"location","type":"text"},{"options":["Pristine","Good","Fair","Damaged"],"label":"Condition","key":"condition","type":"select"},{"label":"Evidence Photo","key":"evidence_photo","type":"image"},{"placeholder":"Additional notes...","label":"Notes","key":"notes","type":"textarea"}]', 'System', 1773794336, 1773794336),
	(4, 1, 'Arrest Warrant Application', '<h2>Arrest Warrant Application</h2><p><strong>Requesting Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><hr><h3>Subject Information</h3><p><strong>Name:</strong> {suspect_name}</p><hr><h3>Probable Cause</h3><p>{probable_cause}</p><h3>Charges Sought</h3><p>{charges}</p>', 'warrant', '[{"label":"Requesting Officer","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"placeholder":"e.g. John Doe","label":"Suspect Name","key":"suspect_name","type":"text"},{"placeholder":"Describe probable cause...","label":"Probable Cause","key":"probable_cause","type":"textarea"},{"placeholder":"List charges...","label":"Charges Sought","key":"charges","type":"textarea"}]', 'System', 1773794336, 1773794336),
	(5, 1, 'BOLO - Suspect Vehicle', '<h2>BOLO - Suspect Vehicle</h2><p><strong>Issued By:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Priority:</strong> {priority}</p><hr><h3>Vehicle Description</h3><p><strong>Make/Model:</strong> {vehicle_desc}</p><p><strong>Plate:</strong> {plate}</p><p><strong>Color:</strong> {color}</p><hr><h3>Vehicle Photo</h3><p>{vehicle_photo}</p><h3>Reason</h3><p>{reason}</p><h3>Instructions</h3><p>{instructions}</p>', 'bolo', '[{"label":"Issued By","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"options":["Low","Medium","High","Critical"],"label":"Priority","key":"priority","type":"select"},{"placeholder":"e.g. Black Dominator GTX","label":"Vehicle Description","key":"vehicle_desc","type":"text"},{"placeholder":"e.g. ABC1234","label":"License Plate","key":"plate","type":"text"},{"placeholder":"e.g. Black","label":"Color","key":"color","type":"text"},{"label":"Vehicle Photo","key":"vehicle_photo","type":"image"},{"placeholder":"Describe reason...","label":"Reason for BOLO","key":"reason","type":"textarea"},{"placeholder":"e.g. Do not approach, notify dispatch","label":"Instructions","key":"instructions","type":"textarea"}]', 'System', 1773794336, 1773794336),
	(6, 2, 'Traffic Stop Report', '<h2>Traffic Stop Report</h2><p><strong>Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Location:</strong> {location}</p><hr><h3>Vehicle Information</h3><p><strong>Plate:</strong> {plate}</p><p><strong>Make/Model:</strong> {vehicle_model}</p><hr><h3>Narrative</h3><p>{narrative}</p>', 'incident', '[{"key":"officer_name","label":"Reporting Officer","type":"staff"},{"key":"date","label":"Date of Stop","type":"date"},{"type":"text","key":"location","label":"Location","placeholder":"e.g. Route 68 & Senora Fwy"},{"type":"text","key":"plate","label":"License Plate","placeholder":"e.g. ABC1234"},{"type":"text","key":"vehicle_model","label":"Vehicle Make/Model","placeholder":"e.g. White Sultan RS"},{"type":"textarea","key":"narrative","label":"Narrative","placeholder":"Describe the stop..."},{"key":"type","unchecked_value":"Citation","placeholder":"","label":"Type","type":"checkbox","checked_value":"Writen Warning"}]', 'System', 1773794375, 1774929562),
	(7, 2, 'Use of Force Incident', '<h2>Use of Force Report</h2><p><strong>Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Force Level:</strong> {force_level}</p><p><strong>Body Camera:</strong> {body_camera}</p><hr><h3>Subject</h3><p><strong>Name:</strong> {suspect_name}</p><hr><h3>Incident Summary</h3><p>{summary}</p><h3>Injuries</h3><p>{injuries}</p>', 'incident', '[{"label":"Officer","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"options":["Level 1 - Verbal","Level 2 - Physical","Level 3 - Less-Lethal","Level 4 - Lethal"],"label":"Force Level","key":"force_level","type":"select"},{"label":"Body Camera Active","key":"body_camera","unchecked_value":"Inactive","checked_value":"Active","type":"checkbox"},{"placeholder":"e.g. John Doe","label":"Subject Name","key":"suspect_name","type":"text"},{"placeholder":"Describe what happened...","label":"Summary","key":"summary","type":"textarea"},{"placeholder":"Describe any injuries...","label":"Injuries Sustained","key":"injuries","type":"textarea"}]', 'System', 1773794375, 1773794375),
	(8, 2, 'Evidence Collection Form', '<h2>Evidence Collection Log</h2><p><strong>Collector:</strong> {collector_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Case #:</strong> {case_number}</p><hr><h3>Evidence Description</h3><p><strong>Type:</strong> {evidence_type}</p><p><strong>Location Found:</strong> {location}</p><p><strong>Condition:</strong> {condition}</p><hr><h3>Evidence Photo</h3><p>{evidence_photo}</p><h3>Chain of Custody Notes</h3><p>{notes}</p>', 'evidence', '[{"label":"Collector","key":"collector_name","type":"staff"},{"label":"Collection Date","key":"date","type":"date"},{"placeholder":"e.g. 2024-0451","label":"Case Number","key":"case_number","type":"text"},{"options":["Firearm","Narcotics","Documents","Digital Media","Biological","Vehicle","Other"],"label":"Evidence Type","key":"evidence_type","type":"select"},{"placeholder":"e.g. 123 Grove St","label":"Location Found","key":"location","type":"text"},{"options":["Pristine","Good","Fair","Damaged"],"label":"Condition","key":"condition","type":"select"},{"label":"Evidence Photo","key":"evidence_photo","type":"image"},{"placeholder":"Additional notes...","label":"Notes","key":"notes","type":"textarea"}]', 'System', 1773794375, 1773794375),
	(9, 2, 'Arrest Warrant Application', '<h2>Arrest Warrant Application</h2><p><strong>Requesting Officer:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><hr><h3>Subject Information</h3><p><strong>Name:</strong> {suspect_name}</p><hr><h3>Probable Cause</h3><p>{probable_cause}</p><h3>Charges Sought</h3><p>{charges}</p>', 'warrant', '[{"label":"Requesting Officer","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"placeholder":"e.g. John Doe","label":"Suspect Name","key":"suspect_name","type":"text"},{"placeholder":"Describe probable cause...","label":"Probable Cause","key":"probable_cause","type":"textarea"},{"placeholder":"List charges...","label":"Charges Sought","key":"charges","type":"textarea"}]', 'System', 1773794375, 1773794375),
	(10, 2, 'BOLO - Suspect Vehicle', '<h2>BOLO - Suspect Vehicle</h2><p><strong>Issued By:</strong> {officer_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Priority:</strong> {priority}</p><hr><h3>Vehicle Description</h3><p><strong>Make/Model:</strong> {vehicle_desc}</p><p><strong>Plate:</strong> {plate}</p><p><strong>Color:</strong> {color}</p><hr><h3>Vehicle Photo</h3><p>{vehicle_photo}</p><h3>Reason</h3><p>{reason}</p><h3>Instructions</h3><p>{instructions}</p>', 'bolo', '[{"label":"Issued By","key":"officer_name","type":"staff"},{"label":"Date","key":"date","type":"date"},{"options":["Low","Medium","High","Critical"],"label":"Priority","key":"priority","type":"select"},{"placeholder":"e.g. Black Dominator GTX","label":"Vehicle Description","key":"vehicle_desc","type":"text"},{"placeholder":"e.g. ABC1234","label":"License Plate","key":"plate","type":"text"},{"placeholder":"e.g. Black","label":"Color","key":"color","type":"text"},{"label":"Vehicle Photo","key":"vehicle_photo","type":"image"},{"placeholder":"Describe reason...","label":"Reason for BOLO","key":"reason","type":"textarea"},{"placeholder":"e.g. Do not approach, notify dispatch","label":"Instructions","key":"instructions","type":"textarea"}]', 'System', 1773794375, 1773794375),
	(11, 2, 'Disciplinary Report', '<p><strong>DISCIPLINARY REPORT</strong><br><br>----------------------------------------<br><br>**Officer Information**<br>Name: {officer_name} <br>Callsign: {officer_callsign} <br>Rank: {officer_rank} <br><br>**Reporting Supervisor**<br>{reporting_supervisor} <br><br>----------------------------------------<br><br>**Incident Details**<br>Date: {incident_date} <br>Time: {incident_time} <br>Location: {incident_location} <br><br>----------------------------------------<br><br>**Allegation(s)**<br>{allegation} <br><br>----------------------------------------<br><br>**Narrative**<br>{narrative} <br><br>----------------------------------------<br><br>**Policy Violations**<br>{violations} <br><br>----------------------------------------<br><br>**Evidence**<br>{evidence} <br><br>----------------------------------------<br><br>**Recommended Disciplinary Action**<br>{disciplinary_action} <br><br>----------------------------------------<br><br>**Supervisor Notes**<br>(Complete upon review)</p>', 'report', '[{"placeholder":"","type":"staff","key":"officer_name","label":"Officer Name"},{"placeholder":"","type":"number","key":"officer_callsign","label":"Callsign"},{"placeholder":"","type":"text","key":"officer_rank","label":"Rank"},{"placeholder":"","type":"text","key":"reporting_supervisor","label":"Reporting Supervisor"},{"placeholder":"","type":"date","key":"incident_date","label":"Incident Date"},{"placeholder":"","type":"text","key":"incident_time","label":"Incident Time"},{"placeholder":"","type":"text","key":"incident_location","label":"Location"},{"placeholder":"","type":"textarea","key":"allegation","label":"Allegation(s)"},{"placeholder":"","type":"textarea","key":"narrative","label":"Narrative"},{"placeholder":"","type":"textarea","key":"violations","label":"Policy Violations"},{"placeholder":"","type":"textarea","key":"evidence","label":"Evidence"},{"placeholder":"","type":"textarea","key":"disciplinary_action","label":"Recommended Action"}]', 'Todd Williams', 1773879531, 1773879531),
	(12, 2, 'Training Report', '<p><strong>TRAINING REPORT</strong><br><br>----------------------------------------<br><br>**Trainee Information**<br>Name: {trainee_name} <br>Callsign: {trainee_callsign} <br>Rank: {trainee_rank} <br><br>**Field Training Officer**<br>{fto_name} <br><br>----------------------------------------<br><br>**Training Details**<br>Date: {training_date} <br>Type: {training_type} <br><br>----------------------------------------<br><br>**Scenarios Covered**<br>{scenarios} <br><br>----------------------------------------<br><br>**Performance Summary**<br>{performance} <br><br>----------------------------------------<br><br>**Strengths**<br>{strengths} <br><br>----------------------------------------<br><br>**Weaknesses**<br>{weaknesses} <br><br>----------------------------------------<br><br>**Corrections / Guidance**<br>{corrections} <br><br>----------------------------------------<br><br>**FTO Recommendation**<br>{recommendation} <br><br>----------------------------------------<br><br>**Final Result**<br>{result} <br><br>----------------------------------------<br><br>**Notes**<br>{notes} </p>', 'report', '[{"type":"staff","placeholder":"","key":"trainee_name","label":"Trainee Name"},{"type":"number","placeholder":"","key":"trainee_callsign","label":"Callsign"},{"type":"text","placeholder":"","key":"trainee_rank","label":"Rank"},{"type":"staff","placeholder":"","key":"fto_name","label":"FTO Name"},{"type":"date","placeholder":"","key":"training_date","label":"training_date"},{"type":"text","placeholder":"","key":"training_type","label":"Training Type"},{"type":"textarea","placeholder":"","key":"scenarios","label":"Scenarios Covered"},{"type":"textarea","placeholder":"","key":"performance","label":"Performance Summary"},{"type":"textarea","placeholder":"","key":"strengths","label":"Strengths"},{"type":"textarea","placeholder":"","key":"weaknesses","label":"Weaknesses"},{"type":"textarea","placeholder":"","key":"corrections","label":"Corrections Given"},{"type":"textarea","placeholder":"","key":"recommendation","label":"Recommendation"},{"key":"result","placeholder":"","checked_value":"PASS","type":"checkbox","unchecked_value":"FAIL","label":"Final Result"},{"placeholder":"","type":"textarea","key":"notes","label":"Notes"}]', 'Todd Williams', 1773879799, 1773879938),
	(13, 3, 'Patient Care Report', '<h2>Patient Care Report</h2><p><strong>Medic:</strong> {medic_name}</p><p><strong>Date:</strong> {date}</p><hr><h3>Patient Information</h3><p><strong>Name:</strong> {patient_name}</p><p><strong>Triage Level:</strong> {triage_level}</p><p><strong>Transported:</strong> {transported}</p><hr><h3>Chief Complaint</h3><p>{complaint}</p><h3>Assessment & Vitals</h3><p>{vitals}</p><h3>Treatment Provided</h3><p>{treatment}</p><h3>Disposition</h3><p>{disposition}</p>', 'report', '[{"key":"medic_name","type":"staff","label":"Attending Medic"},{"key":"date","type":"date","label":"Date"},{"key":"patient_name","type":"text","label":"Patient Name","placeholder":"e.g. John Doe"},{"key":"triage_level","type":"select","label":"Triage Level","options":["Green - Minor","Yellow - Delayed","Red - Immediate","Black - Deceased"]},{"key":"transported","type":"checkbox","label":"Transported to Hospital","unchecked_value":"No","checked_value":"Yes"},{"key":"complaint","type":"textarea","label":"Chief Complaint","placeholder":"Describe presenting complaint..."},{"key":"vitals","type":"textarea","label":"Assessment & Vitals","placeholder":"BP, HR, SpO2, GCS, etc."},{"key":"treatment","type":"textarea","label":"Treatment Provided","placeholder":"Medications, procedures, interventions..."},{"key":"disposition","type":"select","label":"Disposition","options":["Treated & Released","Transported to Hospital","Refused Treatment","Deceased on Scene"]}]', 'System', 1774257099, 1774257099),
	(14, 3, 'Medical Emergency Incident', '<h2>Medical Emergency Incident</h2><p><strong>Lead Medic:</strong> {medic_name}</p><p><strong>Date:</strong> {date}</p><p><strong>Severity:</strong> {severity}</p><hr><h3>Scene Information</h3><p><strong>Location:</strong> {location}</p><p><strong>Type:</strong> {incident_type}</p><hr><h3>Patient Count</h3><p>{patient_count}</p><h3>Incident Summary</h3><p>{summary}</p><h3>Resources Deployed</h3><p>{resources}</p>', 'incident', '[{"key":"medic_name","type":"staff","label":"Lead Medic"},{"key":"date","type":"date","label":"Date"},{"key":"severity","type":"select","label":"Severity","options":["Minor","Moderate","Major","Mass Casualty"]},{"key":"location","type":"text","label":"Location","placeholder":"e.g. Del Perro Pier"},{"key":"incident_type","type":"select","label":"Incident Type","options":["Traffic Collision","Shooting","Stabbing","Overdose","Fire","Fall","Other"]},{"key":"patient_count","type":"number","label":"Patient Count","placeholder":"Number of patients treated"},{"key":"summary","type":"textarea","label":"Incident Summary","placeholder":"Describe the incident..."},{"key":"resources","type":"textarea","label":"Resources Deployed","placeholder":"Units, ambulances, helicopters..."}]', 'System', 1774257099, 1774257099),
	(15, 3, 'Toxicology Report', '<h2>Toxicology Report</h2><p><strong>Analyst:</strong> {analyst_name}</p><p><strong>Date:</strong> {date}</p><hr><h3>Subject</h3><p><strong>Name:</strong> {subject_name}</p><p><strong>Sample Type:</strong> {sample_type}</p><hr><h3>Substances Detected</h3><p>{substances}</p><h3>Concentration Levels</h3><p>{levels}</p><h3>Conclusion</h3><p>{conclusion}</p>', 'evidence', '[{"key":"analyst_name","type":"staff","label":"Analyst"},{"key":"date","type":"date","label":"Date of Analysis"},{"key":"subject_name","type":"text","label":"Subject Name","placeholder":"e.g. John Doe"},{"key":"sample_type","type":"select","label":"Sample Type","options":["Blood","Urine","Hair","Saliva","Other"]},{"key":"substances","type":"textarea","label":"Substances Detected","placeholder":"List detected substances..."},{"key":"levels","type":"textarea","label":"Concentration Levels","placeholder":"Measured levels per substance..."},{"key":"conclusion","type":"textarea","label":"Conclusion","placeholder":"Clinical interpretation of results..."}]', 'System', 1774257099, 1774257099),
	(16, 2, 'INVESTIGATIVE INCIDENT REPORT', '<p><strong><u>INVESTIGATIVE INCIDENT REPORT</u></strong><br><br><strong><u>CALL DETAILS:</u></strong><br>Title: {incident_title}<br>Date: {date}<br>Time: {time}<br>Reporting Officer: {reporting_trooper}<br>Location: [Full Location]<br><br>Call Type: <br>Time of Call: <br>Dispatch Notes: <br><br>---<br><br><strong><u>INVOLVED / PERSON(S) OF INTEREST:</u></strong><br>â¢ Name: <br>â¢ DOB: <br>â¢ Description: <br>â¢ Role: (Suspect / Victim / Witness / POI) <br><br>---<br><br><strong><u>VEHICLE INFORMATION:</u></strong><br>â¢ Plate: <br>â¢ Model: <br>â¢ Color: <br>â¢ Additional Description: <br><br>---<br><br><strong><u>EVIDENCE RECOVERED:</u></strong><br>â¢ Type: (Fingerprint, DNA, Weapon, Narcotics, etc.) <br>â¢ Description: <br>â¢ Location Found: <br>â¢ Evidence ID: <br><br>---<br><br><strong><u>INCIDENT SUMMARY:</u></strong><br>[Full detailed narrative of what occurred. Include observations, timeline, suspect actions, and officer response.]<br><br>---<br><br><strong><u>ACTIONS TAKEN:</u></strong><br><br><br>---<br><br><strong><u>ADDITIONAL NOTES:</u></strong><br>â¢ Surveillance / CCTV: <br>â¢ Witness Statements: <br>â¢ Trooper Observations: {trooper_observations}<br><br>---<br><br><strong><u>PROBABLE CAUSE STATEMENT:</u></strong><br>[Explain clearly WHY you believe a crime occurred based on facts, training, and evidence.]<br></p>', 'incident', '[{"key":"reporting_trooper","placeholder":"","type":"staff","label":"Reporting Trooper"},{"key":"time","placeholder":"","type":"text","label":"Time"},{"key":"date","placeholder":"","type":"date","label":"Date"},{"key":"incident_title","placeholder":"","type":"text","label":"Incident Title"},{"key":"trooper_observations","placeholder":"","type":"textarea","label":"Trooper Observations"}]', 'Todd Williams', 1775608037, 1775608037),
	(17, 2, 'INCIDENT REPORT', '<p><strong><u>INCIDENT INFORMATION:</u></strong><br>Incident Title: {incident_title}<br>Date: {date}</p><p>Time: {time}</p><p>Issuing Officer: {reporting_trooper}</p><p>Location: [Location]<br></p><p>---<br></p><p><strong><u>OFFENDER INFORMATION:</u></strong></p><p>â¢ Name:  </p><p>â¢ DOB:  <br>â¢ State ID#:</p><p>â¢ License #:  <br></p><p>---<br></p><p><strong><u>VEHICLE INFORMATION:</u></strong></p><p>â¢ Plate:  </p><p>â¢ Model:  </p><p>â¢ Color:  </p><p>---<br></p><p><strong><u>INCIDENT DETAILS:</u></strong></p><p>[Summary of violation (speeding, reckless driving, etc.)]<br></p><p>---<br></p><p><strong><u>EVIDENCE / OBSERVATION:</u></strong></p><p>â¢ Radar Speed:  </p><p>â¢ Visual Estimate:  </p><p>â¢ Additional Notes:  <br>â¢ Trooper Observations: {trooper_observations}</p>', 'incident', '[{"key":"reporting_trooper","placeholder":"","type":"staff","label":"Reporting Trooper"},{"key":"time","placeholder":"","type":"text","label":"Time"},{"key":"date","placeholder":"","type":"date","label":"Date"},{"key":"incident_title","placeholder":"","type":"text","label":"Incident Title"},{"key":"trooper_observations","placeholder":"","type":"textarea","label":"Trooper Observations"}]', 'Todd Williams', 1775617806, 1775617806);
